// ── ANIMATED PILL TABS ──
// Call after any tab click to slide the highlight to the active tab
function atabsSync(groupId) {
  var wrap = document.getElementById('atabs-' + groupId);
  if (!wrap) return;
  var hl = document.getElementById('atabs-' + groupId + '-hl');
  if (!hl) return;
  var active = wrap.querySelector('.atab.active');
  if (!active) return;
  var wrapRect = wrap.getBoundingClientRect();
  var tabRect  = active.getBoundingClientRect();
  hl.style.left  = (tabRect.left - wrapRect.left) + 'px';
  hl.style.width = tabRect.width + 'px';
}

// Sync all groups at once
function atabsSyncAll() {
  ['svc','status','date','bin','csort','analytics'].forEach(atabsSync);
}

// Patch the existing filter setters to also sync tabs
var _origSetSvc = typeof setSvc === 'function' ? setSvc : null;
var _origSetJobStatus = typeof setJobStatus === 'function' ? setJobStatus : null;
var _origSetJobDateFilter = typeof setJobDateFilter === 'function' ? setJobDateFilter : null;
var _origSetBinDropFilter = typeof setBinDropFilter === 'function' ? setBinDropFilter : null;

function _patchAtabs() {
  // Jobs: service
  if (typeof setSvc === 'function') {
    var _s = setSvc;
    setSvc = function(v, el) {
      _s(v, el);
      if (el) {
        document.querySelectorAll('#atabs-svc .atab').forEach(function(b){ b.classList.remove('active'); });
        el.classList.add('active');
      }
      atabsSync('svc');
    };
  }
  // Jobs: status
  if (typeof setJobStatus === 'function') {
    var _js = setJobStatus;
    setJobStatus = function(v, el) {
      _js(v, el);
      if (el) {
        document.querySelectorAll('#atabs-status .atab').forEach(function(b){ b.classList.remove('active'); });
        el.classList.add('active');
      }
      atabsSync('status');
    };
  }
  // Jobs: date
  if (typeof setJobDateFilter === 'function') {
    var _jd = setJobDateFilter;
    setJobDateFilter = function(v, el) {
      _jd(v, el);
      if (el) {
        document.querySelectorAll('#atabs-date .atab').forEach(function(b){ b.classList.remove('active'); });
        el.classList.add('active');
      }
      atabsSync('date');
    };
  }
  // Jobs: bin drop
  if (typeof setBinDropFilter === 'function') {
    var _bd = setBinDropFilter;
    setBinDropFilter = function(v, el) {
      _bd(v, el);
      if (el) {
        document.querySelectorAll('#atabs-bin .atab').forEach(function(b){ b.classList.remove('active'); });
        el.classList.add('active');
      }
      atabsSync('bin');
    };
  }
  // Clients: sort
  if (typeof setClientSort === 'function') {
    var _cs = setClientSort;
    setClientSort = function(v, el) {
      _cs(v, el);
      if (el) {
        document.querySelectorAll('#atabs-csort .atab').forEach(function(b){ b.classList.remove('active'); });
        el.classList.add('active');
      }
      atabsSync('csort');
    };
  }
  // Analytics: period
  if (typeof setAnalyticsPeriod === 'function') {
    var _ap = setAnalyticsPeriod;
    setAnalyticsPeriod = function(v, el) {
      _ap(v, el);
      if (el) {
        document.querySelectorAll('#atabs-analytics .atab').forEach(function(b){ b.classList.remove('active'); });
        el.classList.add('active');
      }
      atabsSync('analytics');
    };
  }
}

// Run patch + initial sync once DOM is ready
(function() {
  function _initAtabs() {
    _patchAtabs();
    // Small delay so layout is settled before measuring
    setTimeout(atabsSyncAll, 80);
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', _initAtabs);
  } else {
    _initAtabs();
  }
  // Re-sync when jobs view becomes active
  window.addEventListener('resize', atabsSyncAll);
})();


// ─── VIEWS ───
// ─── ANIMATION UTILITIES ───
function animCount(el, target, prefix, suffix, dur){
  if(!el) return;
  prefix = prefix||''; suffix = suffix||''; dur = dur||1420;
  var start=0, startTime=null;
  var isFloat = target !== Math.floor(target);
  function step(ts){
    if(!startTime) startTime=ts;
    var p=Math.min((ts-startTime)/dur,1);
    var ease=1-Math.pow(1-p,3);
    var val=isFloat?(start+(target-start)*ease).toFixed(0):(Math.round(start+(target-start)*ease));
    el.textContent=prefix+val+suffix;
    if(p<1) requestAnimationFrame(step);
    else el.textContent=prefix+(isFloat?target.toFixed(0):target)+suffix;
  }
  requestAnimationFrame(step);
}
function animateBars(container){
  requestAnimationFrame(function(){
    var bars=(container||document).querySelectorAll('.bar-fill.bar-anim');
    bars.forEach(function(b,i){
      var w=b.getAttribute('data-w')||'0%';
      setTimeout(function(){b.style.width=w;},i*40);
    });
  });
}
function animateView(viewEl){
  if(!viewEl) return;
  var children=viewEl.children;
  Array.prototype.forEach.call(children,function(c,i){
    c.style.opacity='0';
    c.style.transform='translateY(20px)';
    c.style.transition='none';
    setTimeout(function(){
      c.style.transition='opacity .28s ease, transform .28s ease';
      c.style.transitionDelay=(i*45)+'ms';
      c.style.opacity='1';
      c.style.transform='translateY(0)';
    },10);
  });
}

var allViews = ['dashboard','jobs','calendar','clients','bininventory','binmap','vehicles','analytics','utilization','pricing','drdcalc','dispatch','leaderboard','advisor'];
var ANALYTICS_USERS = ['Jake','Sam','Barbara'];
function canAccessAnalytics(){
  return currentUser && currentUser.displayName && ANALYTICS_USERS.indexOf(currentUser.displayName)!==-1;
}
function toggleNavSection(id){
  var sec=document.getElementById(id);if(!sec)return;
  var arrow=document.getElementById(id+'-arrow');
  var open=sec.style.display!=='none';
  sec.style.display=open?'none':'block';
  if(arrow)arrow.style.transform=open?'rotate(-90deg)':'rotate(90deg)';
}
function go(name){
  var restricted=['analytics','utilization','leaderboard','advisor'];
  if(restricted.indexOf(name)!==-1 && !canAccessAnalytics()){
    toast('⚠ You don\'t have access to this page.');return;
  }
  document.querySelectorAll('.view').forEach(function(v){v.classList.remove('active');});
  document.querySelectorAll('.nav-item').forEach(function(n){n.classList.remove('active');});
  var el=document.getElementById('view-'+name);
  if(el) el.classList.add('active');
  document.querySelectorAll('.nav-item').forEach(function(n){
    if(n.getAttribute('onclick')==="go('"+name+"')"){n.classList.add('active');
      var parent=n.parentElement;if(parent&&parent.id&&parent.style.display==='none'){parent.style.display='block';var arrow=document.getElementById(parent.id+'-arrow');if(arrow)arrow.style.transform='rotate(90deg)';}
    }
  });
  render(name);
  if(el) animateView(el);
  closeSidebar();
}
function render(name){
  if(name==='dashboard'){ renderDash(); initDashPricingDropdown(); }
  else if(name==='livejobs') renderLiveJobs();
  else if(name==='jobs'){ renderJobs(); setTimeout(atabsSyncAll, 60); }
  else if(name==='calendar') renderCal();
  else if(name==='clients'){ renderClients(); setTimeout(function(){ atabsSync('csort'); }, 60); }
  else if(name==='analytics'){ initAnalytics(); setTimeout(function(){ atabsSync('analytics'); }, 60); }
  else if(name==='utilization') renderUtilization();
  else if(name==='leaderboard') renderLeaderboardPage();
  else if(name==='pricing') renderPricing();
  else if(name==='drdcalc') renderDrdCalc();
  else if(name==='dispatch') renderDispatch();
  else if(name==='binmap') renderMap();
  else if(name==='advisor') renderAdvisor();
  else if(name==='bininventory') renderBinInventory();
  else if(name==='vehicles'){renderVehicles();loadMaintenanceForVehicles().then(renderMaintSections);}
}
function refresh(){var a=document.querySelector('.view.active');if(a)render(a.id.replace('view-',''));}

// ─── BADGES ───
function stb(s){if(s==='Cancelled')return '<span class="badge badge-cancelled">⚪ Cancelled</span>';return '';}
function sb(s){var cls={'Bin Rental':'svc-bin','Junk Removal':'svc-junk','Junk Quote':'svc-quote','Furniture Pickup':'svc-furn','Furniture Delivery':'svc-furn-del'};return '<span class="service-badge '+(cls[s]||'')+'">'+s+'</span>';}
function jid(id,svc){return '<span class="'+jobIdCls(id,svc)+'">'+id+'</span>';}

// ─── DASHBOARD ───
function getWeekStart(offset){var d=new Date();d.setDate(d.getDate()-d.getDay()+(offset*7));d.setHours(0,0,0,0);return d;}
// Shift the dashboard bin date picker by n days and refresh
function shiftDashDate(n){
  var dp=document.getElementById('dash-bin-date');
  var base=dp&&dp.value?dp.value:todayStr();
  var d=new Date(base+'T12:00:00');
  d.setDate(d.getDate()+n);
  dp.value=d.toISOString().split('T')[0];
  updateDashDateLabel();
  refreshDashBinStats();
  refreshDashJobs();
}
function updateDashDateLabel(){
  var dp=document.getElementById('dash-bin-date');
  var lbl=document.getElementById('dash-date-label');
  if(!dp||!lbl)return;
  var val=dp.value||todayStr();
  var d=new Date(val+'T12:00:00');
  lbl.textContent=d.toLocaleDateString('en-US',{weekday:'short',month:'short',day:'numeric'});
}

// Dashboard bin stats — loads all bin jobs into jobs[] exactly like loadBinJobsThenRender,
// then uses the same binsOutOnDate() + per-size loop that renderUtilization uses.
async function refreshDashBinStats(){
  var dp=document.getElementById('dash-bin-date');
  var dateStr=dp&&dp.value?dp.value:todayStr();
  var today=todayStr();
  var activeBins=binItems.filter(function(b){return b.damage!=='oor';});
  var totalBins=activeBins.length;
  var oorCount=binItems.length-totalBins;
  var sizes=['4 yard','7 yard','14 yard','20 yard'];
  var sizeColors={'4 yard':'#4ade80','7 yard':'#f0932b','14 yard':'#f0932b','20 yard':'#e76f7e'};

  // ── Load dropped bin jobs for counting ───────────────────
  try {
    var [rActive, rUpcoming, rFutureDrop, rFutureDate] = await Promise.all([
      db.from('jobs').select('*')
        .eq('service','Bin Rental')
        .eq('bin_instatus','dropped'),
      db.from('jobs').select('*')
        .eq('service','Bin Rental')
        .neq('status','Cancelled')
        .neq('bin_instatus','pickedup')
        .gte('bin_pickup', today),
      db.from('jobs').select('*')
        .eq('service','Bin Rental')
        .neq('status','Cancelled')
        .neq('bin_instatus','pickedup')
        .gte('bin_dropoff', today),
      // Legacy path: booked Bin Rental jobs that only have `date` populated (no bin_dropoff yet)
      db.from('jobs').select('*')
        .eq('service','Bin Rental')
        .neq('status','Cancelled')
        .neq('bin_instatus','pickedup')
        .is('bin_dropoff', null)
        .gte('date', today)
    ]);
    var seen={};
    [(rActive.data||[]),(rUpcoming.data||[]),(rFutureDrop.data||[]),(rFutureDate.data||[])].forEach(function(arr){
      arr.map(dbToJob).forEach(function(j){
        if(!seen[j.id]){
          seen[j.id]=true;
          var idx=jobs.findIndex(function(x){return x.id===j.id;});
          if(idx>=0) jobs[idx]=j; else jobs.push(j);
        }
      });
    });
  } catch(e){ console.error('refreshDashBinStats load error',e); }

  // ── Count bins out: every active dropped job = 1 bin deployed ──────────────
  // A job without a bin_bid assigned is still a bin physically out there.
  var binsOut=0, binsIn=0;
  var sizeTotal={};
  sizes.forEach(function(s){sizeTotal[s]=activeBins.filter(function(b){return b.size===s;}).length;});
  var sizeOut={'4 yard':0,'7 yard':0,'14 yard':0,'20 yard':0};

  if(dateStr===today){
    // Count from loaded jobs: every dropped, non-cancelled bin rental = out
    var droppedJobs=jobs.filter(function(j){
      return j.service==='Bin Rental'&&j.binInstatus==='dropped'&&j.status!=='Cancelled';
    });
    binsOut=droppedJobs.length;
    binsIn=Math.max(0,totalBins-binsOut);
    droppedJobs.forEach(function(j){ if(j.binSize&&sizeOut.hasOwnProperty(j.binSize))sizeOut[j.binSize]++; });
  } else {
    // Forecast for other dates using job date ranges
    jobs.forEach(function(j){
      if(j.service!=='Bin Rental')return;
      if(j.status==='Cancelled')return;
      if(j.binInstatus==='pickedup')return;
      var drop=j.binDropoff||j.date;
      var pick=j.binPickup;
      var active=false;
      if(j.binInstatus==='dropped'&&dateStr>=today){
        // Physically out right now — ignore binDropoff (may be a future swap date).
        // Out from today through the day before pickup; pickup day = bin returns to yard.
        if(!pick||pick<today) active=true;          // overdue or no pickup scheduled
        else active=dateStr<pick;                    // available again on pickup day
      } else if(!drop){
        return;
      } else if(pick){
        active=dateStr>=drop&&dateStr<pick;
      } else {
        var dropD=new Date(drop+'T12:00:00');
        var maxPick=new Date(dropD);maxPick.setDate(maxPick.getDate()+30);
        active=dateStr>=drop&&dateStr<=maxPick.toISOString().split('T')[0];
      }
      if(active&&sizeOut.hasOwnProperty(j.binSize))sizeOut[j.binSize]++;
    });
    binsOut=sizes.reduce(function(sum,s){return sum+sizeOut[s];},0);
    binsIn=Math.max(0,totalBins-binsOut);
  }
  var outPct=totalBins?Math.round(binsOut/totalBins*100):0;

  // Update both the quick-stat pill AND the fleet card bin count
  animCount(document.getElementById('s-bins-out'),binsOut,'','',700);
  animCount(document.getElementById('s-bins-out-fleet'),binsOut,'','',700);
  animCount(document.getElementById('s-bins-in'),binsIn,'','',700);
  var totalEl=document.getElementById('s-bins-total');if(totalEl)animCount(totalEl,totalBins,'','',700);
  var mbEl=document.getElementById('m-bins');if(mbEl)mbEl.textContent=binsOut;
  setTimeout(function(){
    var ob=document.getElementById('s-bins-out-bar');if(ob)ob.style.width=outPct+'%';
    var pl=document.getElementById('s-bins-pct-lbl');if(pl)pl.textContent=outPct+'% deployed';
  },50);

  // Minimal fleet card: big number = available, single "X/Y out" subline,
  // conditional overdue pill in top-right when bins are past pickup but not pickedup.
  var sizeOverdue={'4 yard':0,'7 yard':0,'14 yard':0,'20 yard':0};
  jobs.forEach(function(j){
    if(j.service!=='Bin Rental')return;
    if(j.status==='Cancelled')return;
    if(j.binInstatus!=='dropped')return;
    if(!j.binPickup||j.binPickup>=today)return;
    if(sizeOverdue.hasOwnProperty(j.binSize))sizeOverdue[j.binSize]++;
  });
  var isToday=(dateStr===today);
  var sizeHtml=sizes.map(function(s){
    var out=Math.min(sizeOut[s],sizeTotal[s]);var tot=sizeTotal[s];var inY=Math.max(0,tot-out);
    var od=sizeOverdue[s]||0;
    var isFull=(tot>0&&inY===0);
    // Per-card availability styling
    var availLbl=isFull?'Fully Booked':(isToday?'AVAILABLE':'PROJECTED AVAILABLE');
    var availColor=isFull?'#ff5560':'#22c55e';
    var availStroke=isFull?'#991b1b':'#15803d';
    var availShadow=isFull
      ?'0 2px 10px rgba(220,53,69,.55),0 6px 28px rgba(220,53,69,.3)'
      :'0 2px 10px rgba(34,197,94,.5),0 6px 24px rgba(34,197,94,.22)';
    var availLblColor=isFull?'#ff6b75':'var(--muted)';
    var cardStyle='position:relative;overflow:hidden';
    if(isFull) cardStyle+=';border-top:5px solid #dc3545;background:linear-gradient(180deg,rgba(220,53,69,0.06) 0%,var(--surface) 60%);box-shadow:inset 0 0 0 1px rgba(220,53,69,0.15)';
    var imgUrl='';
    if(s==='4 yard')imgUrl='https://jeffsjunk.ca/wp-content/uploads/4-yard-bin.png';
    else if(s==='14 yard')imgUrl='https://jeffsjunk.ca/wp-content/uploads/14-yard-bin.png';
    else if(s==='20 yard')imgUrl='https://jeffsjunk.ca/wp-content/uploads/20-yard-bin.png';
    // V3-C layout: photo zone on top with size chip + status pill, stats horizontal below
    var photoStyle='position:relative;height:140px;background-color:var(--surface2);border-bottom:1px solid var(--border)';
    if(imgUrl) photoStyle+=';background-image:url('+imgUrl+');background-size:contain;background-position:center;background-repeat:no-repeat';
    if(isFull) photoStyle+=';background-color:#fff5f5';
    var pillHtml='';
    if(od>0) pillHtml='<div style="position:absolute;top:6px;right:6px;background:rgba(220,53,69,.15);color:#dc3545;font-size:9px;font-weight:700;padding:3px 7px;border-radius:10px;letter-spacing:.4px;white-space:nowrap;z-index:2">⚠ '+od+' OVERDUE</div>';
    else if(isFull) pillHtml='<div style="position:absolute;top:6px;right:6px;background:rgba(220,53,69,.18);color:#ff6b75;font-size:9px;font-weight:700;padding:3px 7px;border-radius:10px;letter-spacing:.4px;display:flex;align-items:center;gap:4px;white-space:nowrap;z-index:2"><svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="#ff6b75" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>FULL</div>';
    var bookBtnStyle=isFull?'background:transparent;color:#ff8a92;border:1px dashed rgba(220,53,69,0.5)':'';
    var bookBtnLbl=isFull?'📅 Book Anyway':'📅 Book';
    var stackedLbl = isFull
      ? 'of '+tot+' — sold out'
      : (isToday ? 'of '+tot+' available' : 'of '+tot+' projected');
    return '<div class="bin-size-card" style="'+cardStyle+';padding:0;text-align:center">'
      +'<div style="'+photoStyle+'">'
        +pillHtml
        +'<div style="position:absolute;bottom:6px;left:6px;font-family:\'Bebas Neue\',sans-serif;font-size:13px;letter-spacing:1.5px;font-weight:900;background:rgba(255,255,255,.88);padding:2px 7px;border-radius:5px;color:var(--text)">'+s.toUpperCase()+'</div>'
      +'</div>'
      +'<div style="padding:12px 12px 14px">'
        +'<div style="margin-bottom:10px">'
          +'<div style="font-family:\'Bebas Neue\',sans-serif;font-size:68px;line-height:.9;color:'+availColor+';-webkit-text-stroke:0.5px '+availStroke+';text-shadow:'+availShadow+';font-variant-numeric:tabular-nums">'+inY+'</div>'
          +'<div style="font-size:10px;color:'+availLblColor+';text-transform:uppercase;letter-spacing:1.5px;font-weight:700;margin-top:2px">'+stackedLbl+'</div>'
        +'</div>'
        +'<button onclick="bookBin(\''+s+'\')" class="bin-book-btn" style="font-size:11px;padding:7px 10px'+(bookBtnStyle?';'+bookBtnStyle:'')+'">'+bookBtnLbl+'</button>'
      +'</div>'
      +'</div>';
  }).join('');
  var sc=document.getElementById('dash-bin-by-size');if(sc)sc.innerHTML=sizeHtml;
}
// Legacy aliases — any old calls route to the new Supabase-powered function
function updateDashBinStats(){refreshDashBinStats();}
function updateDashBinStatsDirect(){refreshDashBinStats();}

function renderDashVehicleStatus(){
  var el=document.getElementById('dash-vehicle-status');if(!el)return;
  var dashVehicles=vehicles.filter(function(v){return !v.leaderboardOnly;});
  if(!dashVehicles.length){el.innerHTML='<span style="font-size:11px;color:var(--muted)">No vehicles</span>';return;}
  var todayS=todayStr();
  el.innerHTML=dashVehicles.map(function(v){
    var blocks=vehBlocks[v.vid]||{};
    var todayBlock=blocks[todayS];
    var status,statusCol,statusIcon,statusTip;
    if(todayBlock){
      status=todayBlock.reason||'Blocked';
      statusCol='#dc3545';statusIcon='🔧';statusTip=status+(todayBlock.notes?' — '+todayBlock.notes:'')+' · click to manage';
    } else {
      status='Available';statusCol='#22c55e';statusIcon='';statusTip='Available · click to manage';
    }
    var dotColor=statusCol;
    var menuId='veh-menu-'+v.vid;

    // Assigned crew for today (only show actively assigned)
    var assigned=vehicleAssignments[v.vid]||[];
    var crewNames=assigned.filter(function(a){return !a.endedAt;}).map(function(a){return a.name;}).join(', ');

    // Build crew assignment options for the dropdown
    var crewOpts=crewMembers.map(function(c){
      var isAssigned=assigned.some(function(a){return a.crewMemberId===c.id && !a.endedAt;});
      return '<div style="padding:6px 14px;font-size:12px;cursor:pointer;display:flex;align-items:center;gap:6px;transition:background .15s" onmouseover="this.style.background=\'rgba(59,130,246,.08)\'" onmouseout="this.style.background=\'transparent\'" onclick="event.stopPropagation();toggleCrewAssignment(\''+v.vid+'\',\''+c.id+'\')">'
        +'<span style="width:16px;text-align:center">'+(isAssigned?'✓':'')+'</span>'
        +'<span>'+c.name+'</span>'
        +'</div>';
    }).join('');
    var crewSection=crewMembers.length
      ?'<div style="border-top:1px solid var(--border);padding:4px 14px 2px;font-size:10px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:.5px">Assign Crew</div>'+crewOpts
        +'<div style="padding:6px 14px;font-size:11px;cursor:pointer;border-top:1px solid var(--border);color:var(--accent);transition:background .15s" onmouseover="this.style.background=\'rgba(59,130,246,.08)\'" onmouseout="this.style.background=\'transparent\'" onclick="event.stopPropagation();closeVehMenus();openCrewManager()">+ Manage Crew</div>'
      :'<div style="padding:8px 14px;font-size:11px;cursor:pointer;border-top:1px solid var(--border);color:var(--accent);transition:background .15s" onmouseover="this.style.background=\'rgba(59,130,246,.08)\'" onmouseout="this.style.background=\'transparent\'" onclick="event.stopPropagation();closeVehMenus();openCrewManager()">+ Add Crew Members</div>';

    var menuHtml='<div id="'+menuId+'" style="display:none;position:absolute;top:100%;left:0;margin-top:4px;background:var(--surface);border:1px solid var(--border);border-radius:10px;box-shadow:0 8px 24px rgba(0,0,0,.15);z-index:600;min-width:200px;overflow:hidden;max-height:320px;overflow-y:auto">'
      +(todayBlock
        ?'<div style="padding:8px 14px;font-size:12px;cursor:pointer;transition:background .15s" onmouseover="this.style.background=\'rgba(34,197,94,.07)\'" onmouseout="this.style.background=\'transparent\'" onclick="event.stopPropagation();markVehicleOperational(\''+v.vid+'\')">✅ Mark Operational</div>'
        :'<div style="padding:8px 14px;font-size:12px;cursor:pointer;transition:background .15s" onmouseover="this.style.background=\'rgba(220,53,69,.08)\'" onmouseout="this.style.background=\'transparent\'" onclick="event.stopPropagation();markVehicleNotOperational(\''+v.vid+'\')">🔧 Not Operational</div>')
      +crewSection
      +'<div style="padding:8px 14px;font-size:12px;cursor:pointer;border-top:1px solid var(--border);transition:background .15s" onmouseover="this.style.background=\'rgba(59,130,246,.08)\'" onmouseout="this.style.background=\'transparent\'" onclick="event.stopPropagation();closeVehMenus();go(\'vehicles\')">📋 Manage Vehicles</div>'
    +'</div>';
    return '<div style="position:relative;display:inline-flex;align-items:center;gap:5px;padding:4px 10px;border-radius:20px;background:'+dotColor+'14;border:1px solid '+dotColor+'33;cursor:pointer;white-space:nowrap;font-size:12px" title="'+statusTip+'" onclick="event.stopPropagation();toggleVehMenu(\''+menuId+'\')">'
      +'<span style="width:7px;height:7px;border-radius:50%;background:'+dotColor+';flex-shrink:0"></span>'
      +'<span style="font-weight:600;color:var(--text)">'+v.name+'</span>'
      +(crewNames?'<span style="font-size:10px;color:var(--muted);max-width:120px;overflow:hidden;text-overflow:ellipsis">'+crewNames+'</span>':'')
      +(statusIcon?'<span style="font-size:10px">'+statusIcon+'</span>':'')
      +menuHtml
      +'</div>';
  }).join('');
}

function markVehicleNotOperational(vid){
  closeVehMenus();
  var today=todayStr();
  if(!vehBlocks[vid])vehBlocks[vid]={};
  vehBlocks[vid][today]={reason:'Service / Repair',notes:'Marked not operational from dashboard',openEnded:true,openFrom:today};
  saveVehBlocks(vid);renderDashVehicleStatus();renderCal();
  toast('Vehicle marked not operational (ongoing until you mark it operational).');
}
function markVehicleOperational(vid){
  closeVehMenus();
  if(!vehBlocks[vid])return;
  // Remove ALL open-ended blocks (past + present + future) so extendOpenBlocks won't recreate them
  var toRemove=Object.keys(vehBlocks[vid]).filter(function(d){return vehBlocks[vid][d].openEnded;});
  toRemove.forEach(function(d){delete vehBlocks[vid][d];});
  // Also clear today even if not open-ended
  var today=todayStr();
  if(vehBlocks[vid][today])delete vehBlocks[vid][today];
  saveVehBlocks(vid);renderDashVehicleStatus();renderCal();
  toast('Vehicle marked operational.');
}
function toggleVehMenu(menuId){
  var m=document.getElementById(menuId);if(!m)return;
  var wasOpen=m.style.display!=='none';
  closeVehMenus();
  if(!wasOpen)m.style.display='block';
}
function closeVehMenus(){
  document.querySelectorAll('[id^="veh-menu-"]').forEach(function(el){el.style.display='none';});
}
document.addEventListener('click',function(e){
  if(!e.target.closest('[id^="veh-menu-"]')&&!e.target.closest('#dash-vehicle-status'))closeVehMenus();
  if(!e.target.closest('.lb-assign-card'))document.querySelectorAll('.lb-assign-menu').forEach(function(el){el.style.display='none';});
});

// ── Crew Assignment (toggle a crew member on/off a vehicle for today with timestamps) ──
function toggleCrewAssignment(vid, crewId){
  var todayISO=todayStr();
  if(!vehicleAssignments[vid]) vehicleAssignments[vid]=[];
  var idx=vehicleAssignments[vid].findIndex(function(a){return a.crewMemberId===crewId && !a.endedAt;});
  if(idx>=0){
    // End this assignment (clock out)
    var rec=vehicleAssignments[vid][idx];
    var now=new Date().toISOString();
    rec.endedAt=now;
    db.from('vehicle_assignments').update({ended_at:now}).eq('id',rec.id).then(function(r){
      if(r.error) console.warn('End assignment failed:',r.error.message);
    });
  } else {
    // Start new assignment (clock in)
    var crew=crewMembers.find(function(c){return c.id===crewId;});
    var now=new Date().toISOString();
    var newRec={id:null, crewMemberId:crewId, name:crew?crew.name:'Unknown', startedAt:now, endedAt:null};
    vehicleAssignments[vid].push(newRec);
    db.from('vehicle_assignments').insert({vid:vid, crew_member_id:crewId, assignment_date:todayISO, started_at:now}).select().then(function(r){
      if(r.error) console.warn('Add assignment failed:',r.error.message);
      if(r.data&&r.data[0]) newRec.id=r.data[0].id;
    });
  }
  renderDashVehicleStatus();
}

// ── Crew Manager Modal ──
function openCrewManager(){
  var html='<div class="modal-overlay open" id="crew-modal-overlay" onclick="if(event.target===this)closeCrewManager()">'
    +'<div style="background:var(--surface);border-radius:14px;padding:24px;max-width:380px;width:90%;box-shadow:0 20px 60px rgba(0,0,0,.3)">'
    +'<div style="font-size:16px;font-weight:700;margin-bottom:16px">Manage Crew Members</div>'
    +'<div id="crew-list" style="margin-bottom:12px"></div>'
    +'<div style="display:flex;gap:8px">'
    +'<input id="crew-new-name" type="text" placeholder="New crew member name" style="flex:1;padding:8px 12px;border-radius:8px;border:1px solid var(--border);background:var(--surface2);color:var(--text);font-size:13px" onkeydown="if(event.key===\'Enter\')addCrewMember()">'
    +'<button class="btn btn-primary" onclick="addCrewMember()" style="font-size:12px;padding:6px 14px">Add</button>'
    +'</div>'
    +'<div style="text-align:right;margin-top:16px"><button class="btn btn-ghost" onclick="closeCrewManager()">Done</button></div>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
  renderCrewList();
}
function closeCrewManager(){
  var el=document.getElementById('crew-modal-overlay');
  if(el)el.remove();
  renderDashVehicleStatus();
}
function renderCrewList(){
  var el=document.getElementById('crew-list');if(!el)return;
  if(!crewMembers.length){el.innerHTML='<div style="font-size:12px;color:var(--muted);padding:8px 0">No crew members yet. Add one below.</div>';return;}
  el.innerHTML=crewMembers.map(function(c){
    return '<div style="display:flex;align-items:center;justify-content:space-between;padding:6px 0;border-bottom:1px solid var(--border)">'
      +'<span style="font-size:13px">'+c.name+'</span>'
      +'<button style="background:none;border:none;color:#dc3545;cursor:pointer;font-size:16px;padding:2px 6px" onclick="removeCrewMember(\''+c.id+'\')" title="Remove">×</button>'
      +'</div>';
  }).join('');
}
function addCrewMember(){
  var input=document.getElementById('crew-new-name');if(!input)return;
  var name=input.value.trim();if(!name)return;
  input.value='';
  db.from('crew_members').insert({name:name}).select().then(function(r){
    if(r.error){toast('Failed to add: '+r.error.message);return;}
    if(r.data&&r.data[0]) crewMembers.push({id:r.data[0].id, name:r.data[0].name});
    renderCrewList();
  });
}
function removeCrewMember(id){
  if(!canDelete){ toast('⚠ You don\'t have permission to remove crew.','error'); return; }
  if(!confirm('Remove this crew member?'))return;
  crewMembers=crewMembers.filter(function(c){return c.id!==id;});
  // Remove from all today's assignments
  Object.keys(vehicleAssignments).forEach(function(vid){
    vehicleAssignments[vid]=vehicleAssignments[vid].filter(function(a){return a.crewMemberId!==id;});
  });
  db.from('crew_members').update({active:false}).eq('id',id).then(function(r){
    if(r.error) console.warn('Remove crew failed:',r.error.message);
  });
  renderCrewList();
}

function changeVehicleStatus(vid,newStatus){
  var v=vehicles.find(function(vv){return vv.vid===vid;});
  if(!v)return;
  v.vehicleStatus=newStatus;
  db.from('vehicles').update({vehicle_status:newStatus}).eq('vid',vid).then(function(r){
    if(r.error)console.warn('Update vehicle status failed:',r.error.message);
  });
  renderDashVehicleStatus();
  // Re-render calendar so blocks show/hide immediately
  renderCal();
}

// ── Leaderboard shared helpers ──
var activeLeaderboard='vehicles'; // 'vehicles' or 'crew'

function switchLeaderboard(tab){
  activeLeaderboard=tab;
  // Update dashboard tabs
  var vBtn=document.getElementById('lb-tab-vehicles');
  var cBtn=document.getElementById('lb-tab-crew');
  if(vBtn) vBtn.style.cssText='font-size:11px;padding:3px 10px;border-radius:6px;font-weight:600;'+(tab==='vehicles'?'background:rgba(34,197,94,.12);color:#15803d;':'');
  if(cBtn) cBtn.style.cssText='font-size:11px;padding:3px 10px;border-radius:6px;font-weight:600;'+(tab==='crew'?'background:rgba(34,197,94,.12);color:#15803d;':'');
  // Update page tabs
  var pvBtn=document.getElementById('lb-page-tab-vehicles');
  var pcBtn=document.getElementById('lb-page-tab-crew');
  if(pvBtn) pvBtn.style.cssText='font-size:12px;padding:5px 14px;border-radius:8px;font-weight:600;'+(tab==='vehicles'?'background:rgba(34,197,94,.12);color:#15803d;':'');
  if(pcBtn) pcBtn.style.cssText='font-size:12px;padding:5px 14px;border-radius:8px;font-weight:600;'+(tab==='crew'?'background:rgba(34,197,94,.12);color:#15803d;':'');
  // Use full page render if on leaderboard page, otherwise simple dashboard render
  var pageView=document.getElementById('view-leaderboard');
  if(pageView&&pageView.classList.contains('active')) renderLeaderboardPage();
  else renderActiveLeaderboard();
}
function getLeaderboardTargets(){
  var el=document.getElementById('dash-leaderboard');
  var periodEl=document.getElementById('leaderboard-period');
  return {el:el,periodEl:periodEl};
}
function renderActiveLeaderboard(){
  if(activeLeaderboard==='crew') renderCrewLeaderboard();
  else renderDriverLeaderboard();
}

function leaderboardEvtRow(label,count,color,icon){
  var barW=count?Math.min(100,count*15):0;
  return '<div style="display:flex;align-items:center;gap:8px;padding:3px 0">'
    +'<div style="width:14px;text-align:center;font-size:11px">'+icon+'</div>'
    +'<div style="width:100px;font-size:11px;color:var(--muted)">'+label+'</div>'
    +'<div style="flex:1;height:6px;background:rgba(0,0,0,.05);border-radius:3px;min-width:60px"><div style="height:100%;width:'+barW+'%;background:'+color+';border-radius:3px;transition:width .3s"></div></div>'
    +'<div style="width:28px;text-align:right;font-weight:700;font-size:12px;color:'+(count?color:'var(--muted)')+'">'+count+'</div>'
  +'</div>';
}

function leaderboardCleanBadge(totalEvents){
  return totalEvents===0
    ?'<div style="display:inline-flex;align-items:center;gap:4px;margin-top:4px;padding:2px 10px;border-radius:20px;background:rgba(34,197,94,.08);color:#16a34a;font-size:10px;font-weight:700;letter-spacing:.3px">✓ CLEAN RECORD</div>'
    :'<div style="display:inline-flex;align-items:center;gap:4px;margin-top:4px;padding:2px 10px;border-radius:20px;background:rgba(220,53,69,.08);color:#dc3545;font-size:10px;font-weight:700;letter-spacing:.3px">'+totalEvents+' event'+(totalEvents!==1?'s':'')+'</div>';
}

// ── Vehicle Leaderboard ──
async function renderDriverLeaderboard(){
  var t=getLeaderboardTargets();
  var el=t.el;if(!el)return;
  var days=t.periodEl?parseInt(t.periodEl.value):7;
  var fromDate=new Date();fromDate.setDate(fromDate.getDate()-days);
  var fromStr=fromDate.toISOString().split('T')[0];

  el.innerHTML='<div style="color:var(--muted);font-size:12px;text-align:center;padding:16px">Loading...</div>';

  var res=await db.from('driver_scores').select('*').gte('period_date',fromStr).order('period_date',{ascending:false});
  var rows=res.data||[];

  var vidSet={};vehicles.forEach(function(v){vidSet[v.vid]=true;});
  rows=rows.filter(function(r){return vidSet[r.vid];});

  var periodLabel=days===1?'Yesterday':(days+' Days');

  if(!rows.length){
    el.innerHTML='<div style="color:var(--muted);font-size:13px;text-align:center;padding:20px">No safety data for '+periodLabel+'. Scores are collected from Geotab every 6 hours.</div>';
    return;
  }

  var byVid={};
  rows.forEach(function(r){
    if(!byVid[r.vid]) byVid[r.vid]={vid:r.vid,name:r.driver_name,days:0,safety:0,harshBrake:0,harshAccel:0,speeding:0,seatbelt:0,cornering:0,distance:0,driveMin:0,idleMin:0};
    var d=byVid[r.vid];
    d.days++;d.name=r.driver_name||d.name;
    d.safety+=Number(r.safety_score);
    d.harshBrake+=r.harsh_braking;d.harshAccel+=r.harsh_accel;d.speeding+=r.speeding_events;d.seatbelt+=r.seatbelt_off;d.cornering+=(r.cornering_events||0);
    d.distance+=Number(r.distance_km);d.driveMin+=r.drive_minutes;d.idleMin+=r.idle_minutes;
  });

  var drivers=Object.values(byVid).map(function(d){
    d.avgSafety=d.days?Math.round(d.safety/d.days*10)/10:0;
    d.totalEvents=d.harshBrake+d.harshAccel+d.speeding+d.seatbelt+d.cornering;
    return d;
  });
  drivers.sort(function(a,b){return b.avgSafety-a.avgSafety;});

  var vehMap={};vehicles.forEach(function(v){vehMap[v.vid]={name:v.name,color:v.color};});

  var medals=['🥇','🥈','🥉'];
  el.innerHTML=drivers.map(function(d,i){
    var v=vehMap[d.vid]||{name:d.name,color:'#22c55e'};
    var medal=i<3?medals[i]:'<span style="font-size:14px;color:var(--muted);font-weight:700;width:22px;display:inline-block;text-align:center">'+(i+1)+'</span>';
    var safeColor=d.avgSafety>=90?'#22c55e':d.avgSafety>=70?'#e67e22':'#dc3545';

    var evtHtml=leaderboardEvtRow('Hard Braking',d.harshBrake,'#dc3545','🛑')
      +leaderboardEvtRow('Hard Accel',d.harshAccel,'#f97316','⚡')
      +leaderboardEvtRow('Speeding',d.speeding,'#e67e22','🏎️')
      +leaderboardEvtRow('Seatbelt Off',d.seatbelt,'#dc2626','🔓')
      +leaderboardEvtRow('Cornering',d.cornering,'#8b5cf6','↩️');

    return '<div style="border:1px solid var(--border);border-radius:12px;margin-bottom:10px;background:var(--surface2);overflow:hidden;transition:box-shadow .15s" onmouseover="this.style.boxShadow=\'0 2px 12px rgba(34,197,94,.08)\'" onmouseout="this.style.boxShadow=\'none\'">'
      +'<div style="display:flex;align-items:center;gap:12px;padding:12px 16px">'
        +'<div style="font-size:22px;flex-shrink:0;width:30px;text-align:center">'+medal+'</div>'
        +'<div style="flex:1;min-width:0">'
          +'<div style="font-weight:700;font-size:15px;display:flex;align-items:center;gap:6px"><span style="width:9px;height:9px;border-radius:50%;background:'+(v.color||'#22c55e')+'"></span>'+(v.name||d.name)+'</div>'
          +'<div style="font-size:11px;color:var(--muted);margin-top:1px">'+Math.round(d.distance)+' km · '+d.days+' day'+(d.days!==1?'s':'')+(d.driveMin?' · '+Math.round(d.driveMin)+' min driving':'')+'</div>'
        +'</div>'
        +'<div style="text-align:center;flex-shrink:0">'
          +'<div style="font-family:\'Bebas Neue\',sans-serif;font-size:38px;color:'+safeColor+';line-height:1">'+d.avgSafety+'</div>'
          +'<div style="font-size:8px;color:var(--muted);text-transform:uppercase;letter-spacing:.5px;font-weight:600">Safety Score</div>'
        +'</div>'
      +'</div>'
      +'<div style="padding:6px 16px 12px 58px;border-top:1px solid var(--border);background:rgba(0,0,0,.01)">'
        +evtHtml
        +leaderboardCleanBadge(d.totalEvents)
      +'</div>'
    +'</div>';
  }).join('');
}

// ── Crew Leaderboard ──
async function renderCrewLeaderboard(){
  var t=getLeaderboardTargets();
  var el=t.el;if(!el)return;
  var days=t.periodEl?parseInt(t.periodEl.value):7;
  var fromDate=new Date();fromDate.setDate(fromDate.getDate()-days);
  var fromStr=fromDate.toISOString().split('T')[0];

  el.innerHTML='<div style="color:var(--muted);font-size:12px;text-align:center;padding:16px">Loading...</div>';

  var res=await db.from('crew_driver_scores').select('*').gte('period_date',fromStr).order('period_date',{ascending:false});
  var rows=res.data||[];

  var periodLabel=days===1?'Yesterday':(days+' Days');

  if(!rows.length){
    el.innerHTML='<div style="color:var(--muted);font-size:13px;text-align:center;padding:20px">No crew safety data for '+periodLabel+'. Crew scores are generated when drivers are assigned to vehicles.</div>';
    return;
  }

  // Aggregate by crew_member_id
  var byCrew={};
  rows.forEach(function(r){
    var cid=r.crew_member_id;
    if(!byCrew[cid]) byCrew[cid]={crewId:cid,days:0,safety:0,harshBrake:0,harshAccel:0,speeding:0,seatbelt:0,cornering:0,distance:0,driveMin:0,vids:{}};
    var d=byCrew[cid];
    d.days++;
    d.safety+=Number(r.safety_score);
    d.harshBrake+=r.harsh_braking;d.harshAccel+=r.harsh_accel;d.speeding+=r.speeding_events;d.seatbelt+=r.seatbelt_off;d.cornering+=(r.cornering_events||0);
    d.distance+=Number(r.distance_km||0);d.driveMin+=(r.drive_minutes||0);
    (r.vehicles_driven||[]).forEach(function(v){d.vids[v]=true;});
  });

  // Map crew IDs to names
  var crewMap={};crewMembers.forEach(function(c){crewMap[c.id]=c.name;});

  var crew=Object.values(byCrew).map(function(d){
    d.name=crewMap[d.crewId]||'Unknown';
    d.avgSafety=d.days?Math.round(d.safety/d.days*10)/10:0;
    d.totalEvents=d.harshBrake+d.harshAccel+d.speeding+d.seatbelt+d.cornering;
    d.vehicleCount=Object.keys(d.vids).length;
    return d;
  });
  crew.sort(function(a,b){return b.avgSafety-a.avgSafety;});

  var medals=['🥇','🥈','🥉'];
  el.innerHTML=crew.map(function(d,i){
    var medal=i<3?medals[i]:'<span style="font-size:14px;color:var(--muted);font-weight:700;width:22px;display:inline-block;text-align:center">'+(i+1)+'</span>';
    var safeColor=d.avgSafety>=90?'#22c55e':d.avgSafety>=70?'#e67e22':'#dc3545';

    var evtHtml=leaderboardEvtRow('Hard Braking',d.harshBrake,'#dc3545','🛑')
      +leaderboardEvtRow('Hard Accel',d.harshAccel,'#f97316','⚡')
      +leaderboardEvtRow('Speeding',d.speeding,'#e67e22','🏎️')
      +leaderboardEvtRow('Seatbelt Off',d.seatbelt,'#dc2626','🔓')
      +leaderboardEvtRow('Cornering',d.cornering,'#8b5cf6','↩️');

    return '<div style="border:1px solid var(--border);border-radius:12px;margin-bottom:10px;background:var(--surface2);overflow:hidden;transition:box-shadow .15s" onmouseover="this.style.boxShadow=\'0 2px 12px rgba(34,197,94,.08)\'" onmouseout="this.style.boxShadow=\'none\'">'
      +'<div style="display:flex;align-items:center;gap:12px;padding:12px 16px">'
        +'<div style="font-size:22px;flex-shrink:0;width:30px;text-align:center">'+medal+'</div>'
        +'<div style="flex:1;min-width:0">'
          +'<div style="font-weight:700;font-size:15px">'+d.name+'</div>'
          +'<div style="font-size:11px;color:var(--muted);margin-top:1px">'+Math.round(d.distance)+' km · '+d.days+' day'+(d.days!==1?'s':'')+' · '+d.vehicleCount+' vehicle'+(d.vehicleCount!==1?'s':'')+(d.driveMin?' · '+Math.round(d.driveMin)+' min driving':'')+'</div>'
        +'</div>'
        +'<div style="text-align:center;flex-shrink:0">'
          +'<div style="font-family:\'Bebas Neue\',sans-serif;font-size:38px;color:'+safeColor+';line-height:1">'+d.avgSafety+'</div>'
          +'<div style="font-size:8px;color:var(--muted);text-transform:uppercase;letter-spacing:.5px;font-weight:600">Safety Score</div>'
        +'</div>'
      +'</div>'
      +'<div style="padding:6px 16px 12px 58px;border-top:1px solid var(--border);background:rgba(0,0,0,.01)">'
        +evtHtml
        +leaderboardCleanBadge(d.totalEvents)
      +'</div>'
    +'</div>';
  }).join('');
}

// Initialize leaderboard tab styling on load
document.addEventListener('DOMContentLoaded',function(){
  var sel=document.getElementById('leaderboard-period');
  if(sel)sel.addEventListener('change',function(){renderActiveLeaderboard();});
  switchLeaderboard('vehicles');
  initLeaderboardPage();
});

// ══════════════════════════════════════════════════════════
// ── Enhanced Leaderboard Page ──
// ══════════════════════════════════════════════════════════

var _lbPeriodMode='week';
var _lbTrendChart=null;
var _lbEventsChart=null;
var _lbIdleChart=null;
var _lbDistanceChart=null;
var _lbImprovChart=null;

// ── Crew-to-vehicle auto-assignments ──
// locked: true = cannot be removed (Max, Darrin)
// locked: false = auto-assigned daily but user can remove (Neil, Jordan, Josh)
var AUTO_ASSIGNMENTS=[
  {crew:'Max',    vehicleMatch:'SILVERADO',      locked:true},
  {crew:'Darrin', vehicleMatch:'Darrin Truck',    locked:true},
  {crew:'Neil',   vehicleMatch:'2020',            locked:false},
  {crew:'Jordan', vehicleMatch:'Furniture Bank',  locked:false},
  {crew:'Josh',   vehicleMatch:'L7 2023',         locked:false}
];

function isPermanentAssignment(crewName, vid){
  var v=vehicles.find(function(vv){return vv.vid===vid;});
  if(!v) return false;
  return AUTO_ASSIGNMENTS.some(function(pa){
    return pa.locked && v.name.indexOf(pa.vehicleMatch)>=0 && crewName.toLowerCase()===pa.crew.toLowerCase();
  });
}

function ensureAutoAssignments(){
  var todayISO=todayStr();
  AUTO_ASSIGNMENTS.forEach(function(pa){
    var v=vehicles.find(function(vv){return vv.name.indexOf(pa.vehicleMatch)>=0;});
    var c=crewMembers.find(function(cc){return cc.name.toLowerCase()===pa.crew.toLowerCase();});
    if(!v||!c) return;
    if(!vehicleAssignments[v.vid]) vehicleAssignments[v.vid]=[];
    var already=vehicleAssignments[v.vid].some(function(a){return a.crewMemberId===c.id && !a.endedAt;});
    if(already) return;
    // Auto-assign
    var now=new Date().toISOString();
    var newRec={id:null, crewMemberId:c.id, name:c.name, startedAt:now, endedAt:null};
    vehicleAssignments[v.vid].push(newRec);
    db.from('vehicle_assignments').upsert({vid:v.vid, crew_member_id:c.id, assignment_date:todayISO, started_at:now},{onConflict:'vid,crew_member_id,assignment_date',ignoreDuplicates:true}).select().then(function(r){
      if(r.error) console.warn('Auto-assignment failed:',r.error.message);
      if(r.data&&r.data[0]) newRec.id=r.data[0].id;
    });
  });
}

function renderLbAssignments(){
  var grid=document.getElementById('lb-assignments-grid');
  if(!grid) return;
  var allVehs=vehicles.filter(function(v){return v.active!==false;});
  grid.innerHTML=allVehs.map(function(v){
    var assigned=(vehicleAssignments[v.vid]||[]).filter(function(a){return !a.endedAt;});
    var crewHtml=assigned.length
      ? assigned.map(function(a){
          var perm=isPermanentAssignment(a.name, v.vid);
          return '<span class="lb-assign-crew'+(perm?' lb-assign-perm':'')+'">'
            +(perm?'🔒 ':'')+a.name
            +(perm?'':'<span class="lb-assign-x" onclick="event.stopPropagation();lbUnassignCrew(\''+v.vid+'\',\''+a.crewMemberId+'\')">&times;</span>')
            +'</span>';
        }).join('')
      : '<span style="font-size:11px;color:var(--muted);font-style:italic">No crew</span>';

    var menuId='lb-assign-menu-'+v.vid;
    // Build crew options (exclude already-assigned)
    var assignedIds={};assigned.forEach(function(a){assignedIds[a.crewMemberId]=true;});
    var opts=crewMembers.filter(function(c){return !assignedIds[c.id];}).map(function(c){
      var perm=isPermanentAssignment(c.name, v.vid);
      return '<div class="lb-assign-opt" onclick="event.stopPropagation();lbAssignCrew(\''+v.vid+'\',\''+c.id+'\')">'+c.name+'</div>';
    }).join('');

    return '<div class="lb-assign-card" onclick="lbToggleAssignMenu(\''+menuId+'\')">'
      +'<div class="lb-assign-vname">'+(v.leaderboardOnly?'':'🚛 ')+v.name+'</div>'
      +'<div class="lb-assign-crew-row">'+crewHtml+'</div>'
      +'<div id="'+menuId+'" class="lb-assign-menu" style="display:none;">'
      +(opts||'<div style="padding:8px 12px;font-size:11px;color:var(--muted)">All crew assigned</div>')
      +'</div>'
    +'</div>';
  }).join('');
}

function lbToggleAssignMenu(menuId){
  var m=document.getElementById(menuId);if(!m)return;
  var wasOpen=m.style.display!=='none';
  // Close all menus first
  document.querySelectorAll('.lb-assign-menu').forEach(function(el){el.style.display='none';});
  if(!wasOpen) m.style.display='block';
}

function lbAssignCrew(vid, crewId){
  document.querySelectorAll('.lb-assign-menu').forEach(function(el){el.style.display='none';});
  toggleCrewAssignment(vid, crewId);
  renderLbAssignments();
  renderDashVehicleStatus();
}

function lbUnassignCrew(vid, crewId){
  // Block unassigning permanent crew
  var crew=crewMembers.find(function(c){return c.id===crewId;});
  if(crew && isPermanentAssignment(crew.name, vid)) return;
  toggleCrewAssignment(vid, crewId);
  renderLbAssignments();
  renderDashVehicleStatus();
}

function initLeaderboardPage(){
  // Populate default date pickers
  var now=new Date();
  var wp=document.getElementById('lb-week-pick');
  if(wp){
    var jan4=new Date(now.getFullYear(),0,4);
    var sow=new Date(jan4);sow.setDate(jan4.getDate()-((jan4.getDay()||7)-1));
    var wn=Math.max(1,Math.min(52,Math.floor(1+(now-sow)/(7*86400000))));
    wp.value=now.getFullYear()+'-W'+(wn<10?'0':'')+wn;
  }
  var mp=document.getElementById('lb-month-pick');
  if(mp) mp.value=now.getFullYear()+'-'+(now.getMonth()+1<10?'0':'')+(now.getMonth()+1);

  // Quarter picker
  var qp=document.getElementById('lb-quarter-pick');
  if(qp){
    var html='';
    for(var y=now.getFullYear();y>=now.getFullYear()-2;y--){
      for(var q=4;q>=1;q--){
        var sel=(y===now.getFullYear()&&q===Math.ceil((now.getMonth()+1)/3))?'selected':'';
        html+='<option value="'+y+'-Q'+q+'" '+sel+'>Q'+q+' '+y+'</option>';
      }
    }
    qp.innerHTML=html;
  }

  // Year picker
  var yp=document.getElementById('lb-year-pick');
  if(yp){
    var html='';
    for(var y=now.getFullYear();y>=now.getFullYear()-3;y--){
      html+='<option value="'+y+'"'+(y===now.getFullYear()?' selected':'')+'>'+y+'</option>';
    }
    yp.innerHTML=html;
  }

  // Custom defaults
  var cf=document.getElementById('lb-custom-from');
  var ct=document.getElementById('lb-custom-to');
  if(cf) cf.value=new Date(now.getFullYear(),now.getMonth(),1).toISOString().split('T')[0];
  if(ct) ct.value=now.toISOString().split('T')[0];
}

function setLbPeriodMode(mode,btn){
  _lbPeriodMode=mode;
  document.querySelectorAll('.lb-period-btn').forEach(function(b){b.classList.remove('active');});
  if(btn)btn.classList.add('active');
  ['today','week','month','quarter','year','custom'].forEach(function(m){
    var el=document.getElementById('lb-date-'+m);
    if(el) el.style.display=(m===mode)?'flex':'none';
  });
  renderLeaderboardPage();
}

function getLbDateRange(){
  var now=new Date();
  var from,to;
  if(_lbPeriodMode==='today'){
    from=new Date(now.getFullYear(),now.getMonth(),now.getDate());
    to=new Date(now.getFullYear(),now.getMonth(),now.getDate());
  } else if(_lbPeriodMode==='week'){
    var wp=document.getElementById('lb-week-pick');
    if(wp&&wp.value){
      var parts=wp.value.split('-W');
      var y=parseInt(parts[0]),w=parseInt(parts[1]);
      var jan4=new Date(y,0,4);
      var sow=new Date(jan4);sow.setDate(jan4.getDate()-((jan4.getDay()||7)-1));
      from=new Date(sow);from.setDate(from.getDate()+(w-1)*7);
      to=new Date(from);to.setDate(to.getDate()+6);
    }
  } else if(_lbPeriodMode==='month'){
    var mp=document.getElementById('lb-month-pick');
    if(mp&&mp.value){
      var parts=mp.value.split('-');
      from=new Date(parseInt(parts[0]),parseInt(parts[1])-1,1);
      to=new Date(parseInt(parts[0]),parseInt(parts[1]),0);
    }
  } else if(_lbPeriodMode==='quarter'){
    var qp=document.getElementById('lb-quarter-pick');
    if(qp&&qp.value){
      var parts=qp.value.split('-Q');
      var y=parseInt(parts[0]),q=parseInt(parts[1]);
      from=new Date(y,(q-1)*3,1);
      to=new Date(y,q*3,0);
    }
  } else if(_lbPeriodMode==='year'){
    var yp=document.getElementById('lb-year-pick');
    if(yp&&yp.value){
      var y=parseInt(yp.value);
      from=new Date(y,0,1);
      to=new Date(y,11,31);
    }
  } else if(_lbPeriodMode==='custom'){
    var cf=document.getElementById('lb-custom-from');
    var ct=document.getElementById('lb-custom-to');
    if(cf&&cf.value) from=new Date(cf.value+'T12:00:00');
    if(ct&&ct.value) to=new Date(ct.value+'T12:00:00');
  }
  if(!from) from=new Date(now.getFullYear(),now.getMonth(),now.getDate()-7);
  if(!to) to=now;
  return {
    from:from.toISOString().split('T')[0],
    to:to.toISOString().split('T')[0],
    label:_lbPeriodMode==='today'?'Today — '+from.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'}):
          _lbPeriodMode==='month'?from.toLocaleDateString('en-US',{month:'long',year:'numeric'}):
          _lbPeriodMode==='quarter'?(document.getElementById('lb-quarter-pick')||{}).value||'':
          _lbPeriodMode==='year'?(document.getElementById('lb-year-pick')||{}).value||'':
          from.toLocaleDateString('en-US',{month:'short',day:'numeric'})+' – '+to.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})
  };
}

async function renderLeaderboardPage(){
  // Ensure permanent crew are assigned
  ensureAutoAssignments();
  renderLbAssignments();

  var range=getLbDateRange();
  var isCrewMode=activeLeaderboard==='crew';

  // Fetch data
  var rows=[];
  if(isCrewMode){
    var res=await db.from('crew_driver_scores').select('*').gte('period_date',range.from).lte('period_date',range.to).order('period_date',{ascending:true});
    rows=res.data||[];
  } else {
    var res=await db.from('driver_scores').select('*').gte('period_date',range.from).lte('period_date',range.to).order('period_date',{ascending:true});
    rows=res.data||[];
    var vidSet={};vehicles.forEach(function(v){vidSet[v.vid]=true;});
    rows=rows.filter(function(r){return vidSet[r.vid];});
  }

  renderLbWinnerBanner(rows,range,isCrewMode);
  renderLbStatCards(rows,range,isCrewMode);
  renderLbTrendChart(rows,isCrewMode);
  renderLbEventsChart(rows,isCrewMode);
  renderLbIdleChart(rows,isCrewMode);
  renderLbDistanceChart(rows,isCrewMode);
  renderLbImprovement(rows,range,isCrewMode);
  renderLbRankings(rows,range,isCrewMode);
}

// ── Winner Banner ──
function renderLbWinnerBanner(rows,range,isCrewMode){
  var el=document.getElementById('lb-winner-banner');if(!el)return;
  if(!rows.length){el.style.display='none';return;}

  var agg=aggregateLbRows(rows,isCrewMode);
  if(!agg.length){el.style.display='none';return;}
  agg.sort(function(a,b){return b.avgSafety-a.avgSafety;});
  var winner=agg[0];

  el.style.display='';
  el.innerHTML='<div style="display:flex;align-items:center;gap:16px;flex-wrap:wrap;">'
    +'<div style="font-size:48px;">🏆</div>'
    +'<div style="flex:1;min-width:200px;">'
      +'<div style="font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:var(--accent);margin-bottom:2px;">Top Performer — '+range.label+'</div>'
      +'<div style="font-size:24px;font-weight:800;">'+winner.name+'</div>'
      +'<div style="font-size:13px;color:var(--muted);margin-top:2px;">'+Math.round(winner.distance)+' km driven · '+winner.days+' day'+(winner.days!==1?'s':'')+' active · '+winner.totalEvents+' event'+(winner.totalEvents!==1?'s':'')+'</div>'
    +'</div>'
    +'<div style="text-align:center;">'
      +'<div style="font-family:\'Bebas Neue\',sans-serif;font-size:56px;color:'+(winner.avgSafety>=90?'#22c55e':winner.avgSafety>=70?'#e67e22':'#dc3545')+';line-height:1;">'+winner.avgSafety+'</div>'
      +'<div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:var(--muted);">Avg Safety Score</div>'
    +'</div>'
  +'</div>';
}

// ── Stat Cards ──
function renderLbStatCards(rows,range,isCrewMode){
  var el=document.getElementById('lb-stat-cards');if(!el)return;
  if(!rows.length){el.innerHTML='';return;}

  var agg=aggregateLbRows(rows,isCrewMode);
  var totalEvents=0,totalDist=0,totalDays=0,safetySum=0,cleanCount=0;
  agg.forEach(function(d){
    totalEvents+=d.totalEvents;totalDist+=d.distance;totalDays+=d.days;safetySum+=d.avgSafety;
    if(d.totalEvents===0) cleanCount++;
  });
  var fleetAvg=agg.length?Math.round(safetySum/agg.length*10)/10:0;

  var totalDriveHrs=0;
  agg.forEach(function(d){totalDriveHrs+=d.driveMin;});
  var driveDisplay=totalDriveHrs>=60?Math.round(totalDriveHrs/60)+'h':Math.round(totalDriveHrs)+'m';

  el.innerHTML=lbStatCard('Fleet Avg Safety',fleetAvg,fleetAvg>=90?'#22c55e':fleetAvg>=70?'#e67e22':'#dc3545','📊')
    +lbStatCard('Total Events',totalEvents,totalEvents===0?'#22c55e':'#dc3545','⚠️')
    +lbStatCard('Clean Records',cleanCount+'/'+agg.length,'#22c55e','✅')
    +lbStatCard('Total Distance',Math.round(totalDist)+' km','var(--text)','🛣️')
    +lbStatCard('Drive Time',driveDisplay,'var(--text)','⏱️');
}

function lbStatCard(label,value,color,icon){
  return '<div class="stat-card" style="flex:1;min-width:140px;"><div class="stat-icon">'+icon+'</div><div class="stat-value" style="color:'+color+'">'+value+'</div><div class="stat-label">'+label+'</div></div>';
}

// ── Trend Chart ──
function renderLbTrendChart(rows,isCrewMode){
  var ctx=document.getElementById('lb-trend-chart');if(!ctx)return;
  if(_lbTrendChart){_lbTrendChart.destroy();_lbTrendChart=null;}
  if(!rows.length)return;

  // Group by date and entity
  var entities={};
  rows.forEach(function(r){
    var key=isCrewMode?r.crew_member_id:r.vid;
    if(!entities[key])entities[key]={name:'',dates:{}};
    entities[key].dates[r.period_date]=Number(r.safety_score);
    entities[key].name=isCrewMode?(crewMembers.find(function(c){return c.id===key;})||{}).name||'Unknown':(vehicles.find(function(v){return v.vid===key;})||{}).name||r.driver_name||key;
  });

  var allDates=[];
  rows.forEach(function(r){if(allDates.indexOf(r.period_date)===-1)allDates.push(r.period_date);});
  allDates.sort();

  var colors=['#22c55e','#3b82f6','#f97316','#8b5cf6','#ec4899','#14b8a6','#eab308','#dc3545'];
  var datasets=[];var ci=0;
  Object.keys(entities).forEach(function(key){
    var ent=entities[key];
    var data=allDates.map(function(d){return ent.dates[d]!==undefined?ent.dates[d]:null;});
    datasets.push({
      label:ent.name,
      data:data,
      borderColor:colors[ci%colors.length],
      backgroundColor:colors[ci%colors.length]+'20',
      tension:0.3,
      pointRadius:3,
      pointHoverRadius:6,
      fill:false
    });
    ci++;
  });

  var isDark=document.documentElement.getAttribute('data-theme')==='dark';
  var gridColor=isDark?'rgba(255,255,255,.08)':'rgba(0,0,0,.06)';
  var textColor=isDark?'#aaa':'#666';

  _lbTrendChart=new Chart(ctx,{
    type:'line',
    data:{labels:allDates.map(function(d){return new Date(d+'T12:00:00').toLocaleDateString('en-US',{month:'short',day:'numeric'});}),datasets:datasets},
    options:{
      responsive:true,maintainAspectRatio:false,
      interaction:{mode:'index',intersect:false},
      scales:{
        y:{min:0,max:100,grid:{color:gridColor},ticks:{color:textColor,font:{size:11}}},
        x:{grid:{display:false},ticks:{color:textColor,font:{size:10},maxTicksLimit:15}}
      },
      plugins:{legend:{position:'bottom',labels:{usePointStyle:true,pointStyle:'circle',padding:12,font:{size:11},color:textColor}}}
    }
  });
}

// ── Events Breakdown Chart ──
function renderLbEventsChart(rows,isCrewMode){
  var ctx=document.getElementById('lb-events-chart');if(!ctx)return;
  if(_lbEventsChart){_lbEventsChart.destroy();_lbEventsChart=null;}
  if(!rows.length)return;

  var agg=aggregateLbRows(rows,isCrewMode);
  agg.sort(function(a,b){return b.totalEvents-a.totalEvents;});

  var labels=agg.map(function(d){return d.name;});
  var isDark=document.documentElement.getAttribute('data-theme')==='dark';
  var gridColor=isDark?'rgba(255,255,255,.08)':'rgba(0,0,0,.06)';
  var textColor=isDark?'#aaa':'#666';

  _lbEventsChart=new Chart(ctx,{
    type:'bar',
    data:{
      labels:labels,
      datasets:[
        {label:'Hard Braking',data:agg.map(function(d){return d.harshBrake;}),backgroundColor:'#dc3545'},
        {label:'Hard Accel',data:agg.map(function(d){return d.harshAccel;}),backgroundColor:'#f97316'},
        {label:'Speeding',data:agg.map(function(d){return d.speeding;}),backgroundColor:'#e67e22'},
        {label:'Seatbelt Off',data:agg.map(function(d){return d.seatbelt;}),backgroundColor:'#dc2626'},
        {label:'Cornering',data:agg.map(function(d){return d.cornering;}),backgroundColor:'#8b5cf6'}
      ]
    },
    options:{
      responsive:true,maintainAspectRatio:false,
      scales:{
        x:{stacked:true,grid:{display:false},ticks:{color:textColor,font:{size:10}}},
        y:{stacked:true,grid:{color:gridColor},ticks:{color:textColor,font:{size:11},stepSize:1}}
      },
      plugins:{legend:{position:'bottom',labels:{usePointStyle:true,pointStyle:'rect',padding:12,font:{size:10},color:textColor}}}
    }
  });
}

// ── Idle vs Drive Chart ──
function renderLbIdleChart(rows,isCrewMode){
  var ctx=document.getElementById('lb-idle-chart');if(!ctx)return;
  if(_lbIdleChart){_lbIdleChart.destroy();_lbIdleChart=null;}
  // Manage the "no data" message for crew mode
  var idleWrap=ctx.parentElement;
  var idleMsg=document.getElementById('lb-idle-no-data');
  if(!idleMsg&&idleWrap){idleWrap.insertAdjacentHTML('beforeend','<div id="lb-idle-no-data" style="display:none;color:var(--muted);font-size:13px;text-align:center;padding:40px 0;position:absolute;inset:0;display:none;align-items:center;justify-content:center;">Idle data is only available for vehicles</div>');}
  idleMsg=document.getElementById('lb-idle-no-data');
  if(!rows.length||isCrewMode){
    ctx.style.display='none';
    if(idleMsg)idleMsg.style.display=isCrewMode?'flex':'none';
    return;
  }
  ctx.style.display='';
  if(idleMsg)idleMsg.style.display='none';

  var agg=aggregateLbRows(rows,false);
  agg.sort(function(a,b){return b.driveMin-a.driveMin;});
  var labels=agg.map(function(d){return d.name;});

  var isDark=document.documentElement.getAttribute('data-theme')==='dark';
  var gridColor=isDark?'rgba(255,255,255,.08)':'rgba(0,0,0,.06)';
  var textColor=isDark?'#aaa':'#666';

  _lbIdleChart=new Chart(ctx,{
    type:'bar',
    data:{
      labels:labels,
      datasets:[
        {label:'Drive (min)',data:agg.map(function(d){return Math.round(d.driveMin);}),backgroundColor:'#22c55e'},
        {label:'Idle (min)',data:agg.map(function(d){return Math.round(d.idleMin);}),backgroundColor:'#f97316'}
      ]
    },
    options:{
      responsive:true,maintainAspectRatio:false,
      scales:{
        x:{stacked:true,grid:{display:false},ticks:{color:textColor,font:{size:10}}},
        y:{stacked:true,grid:{color:gridColor},ticks:{color:textColor,font:{size:11}}}
      },
      plugins:{legend:{position:'bottom',labels:{usePointStyle:true,pointStyle:'rect',padding:12,font:{size:10},color:textColor}}}
    }
  });
}

