// ── Improvement Tracker ──
function renderLbImprovement(rows,range,isCrewMode){
  var chartCtx=document.getElementById('lb-improvement-chart');
  var cardsEl=document.getElementById('lb-improvement-cards');
  var sectionEl=document.getElementById('lb-improvement-section');
  if(_lbImprovChart){_lbImprovChart.destroy();_lbImprovChart=null;}
  if(!cardsEl||!sectionEl)return;

  if(rows.length<2){
    sectionEl.style.display='none';
    return;
  }
  sectionEl.style.display='';

  // Sort rows by date and split into first half / second half
  var sorted=rows.slice().sort(function(a,b){return a.period_date.localeCompare(b.period_date);});
  var mid=Math.floor(sorted.length/2);
  var firstHalf=sorted.slice(0,mid);
  var secondHalf=sorted.slice(mid);

  var firstStart=firstHalf.length?firstHalf[0].period_date:'';
  var firstEnd=firstHalf.length?firstHalf[firstHalf.length-1].period_date:'';
  var secondStart=secondHalf.length?secondHalf[0].period_date:'';
  var secondEnd=secondHalf.length?secondHalf[secondHalf.length-1].period_date:'';

  function fd(d){return new Date(d+'T12:00:00').toLocaleDateString('en-US',{month:'short',day:'numeric'});}
  var firstLabel=firstStart?fd(firstStart)+' – '+fd(firstEnd):'First Half';
  var secondLabel=secondStart?fd(secondStart)+' – '+fd(secondEnd):'Second Half';

  // Aggregate each half by entity
  function aggHalf(half){
    var byE={};
    half.forEach(function(r){
      var key=isCrewMode?r.crew_member_id:r.vid;
      if(!byE[key])byE[key]={safety:0,events:0,distance:0,driveMin:0,n:0};
      byE[key].safety+=Number(r.safety_score);
      byE[key].events+=(r.harsh_braking||0)+(r.harsh_accel||0)+(r.speeding_events||0)+(r.seatbelt_off||0)+(r.cornering_events||0);
      byE[key].distance+=Number(r.distance_km||0);
      byE[key].driveMin+=(r.drive_minutes||0);
      byE[key].n++;
    });
    // Compute averages
    Object.keys(byE).forEach(function(k){
      var d=byE[k];
      d.avgSafety=d.n?Math.round(d.safety/d.n*10)/10:0;
      d.avgEvents=d.n?Math.round(d.events/d.n*10)/10:0;
    });
    return byE;
  }

  var first=aggHalf(firstHalf);
  var second=aggHalf(secondHalf);

  // Build improvement data for entities present in both halves
  var allKeys={};
  Object.keys(first).forEach(function(k){allKeys[k]=true;});
  Object.keys(second).forEach(function(k){allKeys[k]=true;});

  var improvements=[];
  Object.keys(allKeys).forEach(function(key){
    var f=first[key]||{avgSafety:0,avgEvents:0,events:0,distance:0,driveMin:0,n:0};
    var s=second[key]||{avgSafety:0,avgEvents:0,events:0,distance:0,driveMin:0,n:0};
    var name;
    if(isCrewMode){
      name=(crewMembers.find(function(c){return c.id===key;})||{}).name||'Unknown';
    } else {
      name=(vehicles.find(function(v){return v.vid===key;})||{}).name||key;
    }
    var safetyDelta=Math.round((s.avgSafety-f.avgSafety)*10)/10;
    var safetyPct=f.avgSafety>0?Math.round((safetyDelta/f.avgSafety)*1000)/10:0;
    var eventsDelta=Math.round((s.avgEvents-f.avgEvents)*10)/10;
    var eventsPct=f.avgEvents>0?Math.round((eventsDelta/f.avgEvents)*1000)/10:0;
    improvements.push({
      key:key,name:name,
      firstSafety:f.avgSafety,secondSafety:s.avgSafety,
      safetyDelta:safetyDelta,safetyPct:safetyPct,
      firstEvents:f.avgEvents,secondEvents:s.avgEvents,
      eventsDelta:eventsDelta,eventsPct:eventsPct,
      firstTotalEvents:f.events,secondTotalEvents:s.events,
      firstDistance:Math.round(f.distance),secondDistance:Math.round(s.distance),
      firstDays:f.n,secondDays:s.n
    });
  });

  improvements.sort(function(a,b){return b.safetyDelta-a.safetyDelta;});

  // ── Chart: grouped bar (first half vs second half safety) ──
  if(chartCtx){
    var isDark=document.documentElement.getAttribute('data-theme')==='dark';
    var gridColor=isDark?'rgba(255,255,255,.08)':'rgba(0,0,0,.06)';
    var textColor=isDark?'#aaa':'#666';

    _lbImprovChart=new Chart(chartCtx,{
      type:'bar',
      data:{
        labels:improvements.map(function(d){return d.name;}),
        datasets:[
          {label:firstLabel+' (avg safety)',data:improvements.map(function(d){return d.firstSafety;}),backgroundColor:'rgba(59,130,246,.6)',borderRadius:4},
          {label:secondLabel+' (avg safety)',data:improvements.map(function(d){return d.secondSafety;}),backgroundColor:'rgba(34,197,94,.7)',borderRadius:4}
        ]
      },
      options:{
        responsive:true,maintainAspectRatio:false,
        scales:{
          x:{grid:{display:false},ticks:{color:textColor,font:{size:11}}},
          y:{min:0,max:100,grid:{color:gridColor},ticks:{color:textColor,font:{size:11}}}
        },
        plugins:{
          legend:{position:'bottom',labels:{usePointStyle:true,pointStyle:'rect',padding:12,font:{size:11},color:textColor}},
          tooltip:{callbacks:{afterBody:function(ctx){
            var i=ctx[0].dataIndex;
            var d=improvements[i];
            return 'Change: '+(d.safetyDelta>=0?'+':'')+d.safetyDelta+' ('+(d.safetyPct>=0?'+':'')+d.safetyPct+'%)';
          }}}
        }
      }
    });
  }

  // ── Cards: detailed breakdown per person ──
  cardsEl.innerHTML=improvements.map(function(d){
    var safeColor=d.safetyDelta>0?'#22c55e':d.safetyDelta<0?'#dc3545':'var(--muted)';
    var evtColor=d.eventsDelta<0?'#22c55e':d.eventsDelta>0?'#dc3545':'var(--muted)';
    var safeArrow=d.safetyDelta>0?'▲':d.safetyDelta<0?'▼':'—';
    var evtArrow=d.eventsDelta<0?'▼':d.eventsDelta>0?'▲':'—';

    // Safety score bar visual
    var firstW=d.firstSafety;
    var secondW=d.secondSafety;

    return '<div style="border:1px solid var(--border);border-radius:10px;padding:14px 16px;margin-bottom:10px;background:var(--surface2)">'
      +'<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;">'
        +'<div style="font-weight:700;font-size:14px;">'+d.name+'</div>'
        +'<div style="display:flex;align-items:center;gap:8px;">'
          +'<span style="font-family:\'Bebas Neue\',sans-serif;font-size:28px;color:'+safeColor+';line-height:1;">'+(d.safetyDelta>=0?'+':'')+d.safetyDelta+'</span>'
          +'<span style="font-size:12px;font-weight:700;color:'+safeColor+';background:'+safeColor+'14;padding:2px 8px;border-radius:6px;">'+(d.safetyPct>=0?'+':'')+d.safetyPct+'%</span>'
        +'</div>'
      +'</div>'
      // Safety score comparison
      +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:10px;">'
        +'<div style="background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:10px 12px;">'
          +'<div style="font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:.5px;color:var(--muted);margin-bottom:4px;">'+firstLabel+'</div>'
          +'<div style="display:flex;align-items:baseline;gap:8px;">'
            +'<span style="font-size:24px;font-weight:800;color:'+(d.firstSafety>=90?'#22c55e':d.firstSafety>=70?'#e67e22':'#dc3545')+'">'+d.firstSafety+'</span>'
            +'<span style="font-size:11px;color:var(--muted)">safety avg</span>'
          +'</div>'
          +'<div style="height:4px;background:rgba(0,0,0,.06);border-radius:2px;margin-top:6px;"><div style="height:100%;width:'+firstW+'%;background:rgba(59,130,246,.5);border-radius:2px;"></div></div>'
          +'<div style="font-size:11px;color:var(--muted);margin-top:6px;">'+d.firstTotalEvents+' events · '+d.firstDistance+' km · '+d.firstDays+' day'+(d.firstDays!==1?'s':'')+'</div>'
        +'</div>'
        +'<div style="background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:10px 12px;">'
          +'<div style="font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:.5px;color:var(--muted);margin-bottom:4px;">'+secondLabel+'</div>'
          +'<div style="display:flex;align-items:baseline;gap:8px;">'
            +'<span style="font-size:24px;font-weight:800;color:'+(d.secondSafety>=90?'#22c55e':d.secondSafety>=70?'#e67e22':'#dc3545')+'">'+d.secondSafety+'</span>'
            +'<span style="font-size:11px;color:var(--muted)">safety avg</span>'
          +'</div>'
          +'<div style="height:4px;background:rgba(0,0,0,.06);border-radius:2px;margin-top:6px;"><div style="height:100%;width:'+secondW+'%;background:rgba(34,197,94,.6);border-radius:2px;"></div></div>'
          +'<div style="font-size:11px;color:var(--muted);margin-top:6px;">'+d.secondTotalEvents+' events · '+d.secondDistance+' km · '+d.secondDays+' day'+(d.secondDays!==1?'s':'')+'</div>'
        +'</div>'
      +'</div>'
      // Events change
      +'<div style="display:flex;gap:16px;font-size:12px;color:var(--muted);border-top:1px solid var(--border);padding-top:8px;">'
        +'<span>Events/day: '+d.firstEvents+' → '+d.secondEvents+' <span style="color:'+evtColor+';font-weight:700">'+evtArrow+' '+(d.eventsPct>=0?'+':'')+d.eventsPct+'%</span></span>'
        +'<span>Distance: '+d.firstDistance+' → '+d.secondDistance+' km</span>'
      +'</div>'
    +'</div>';
  }).join('');
}

// ── Rankings (reuses existing card style) ──
function renderLbRankings(rows,range,isCrewMode){
  var el=document.getElementById('page-leaderboard');if(!el)return;
  var titleEl=document.getElementById('lb-rankings-title');

  if(!rows.length){
    el.innerHTML='<div style="color:var(--muted);font-size:13px;text-align:center;padding:30px">No data for '+range.label+'.</div>';
    if(titleEl)titleEl.textContent='Rankings';
    return;
  }

  var agg=aggregateLbRows(rows,isCrewMode);
  agg.sort(function(a,b){return b.avgSafety-a.avgSafety;});
  if(titleEl)titleEl.textContent='Rankings — '+range.label;

  var vehMap={};vehicles.forEach(function(v){vehMap[v.vid]={name:v.name,color:v.color};});
  var medals=['🥇','🥈','🥉'];

  el.innerHTML=agg.map(function(d,i){
    var medal=i<3?medals[i]:'<span style="font-size:14px;color:var(--muted);font-weight:700;width:22px;display:inline-block;text-align:center">'+(i+1)+'</span>';
    var safeColor=d.avgSafety>=90?'#22c55e':d.avgSafety>=70?'#e67e22':'#dc3545';
    var v=isCrewMode?null:vehMap[d.id];
    var dotHtml=v?'<span style="width:9px;height:9px;border-radius:50%;background:'+(v.color||'#22c55e')+'"></span>':'';

    var evtHtml=leaderboardEvtRow('Hard Braking',d.harshBrake,'#dc3545','🛑')
      +leaderboardEvtRow('Hard Accel',d.harshAccel,'#f97316','⚡')
      +leaderboardEvtRow('Speeding',d.speeding,'#e67e22','🏎️')
      +leaderboardEvtRow('Seatbelt Off',d.seatbelt,'#dc2626','🔓')
      +leaderboardEvtRow('Cornering',d.cornering,'#8b5cf6','↩️');

    // Extra metrics row
    var extraHtml='<div style="display:flex;gap:16px;flex-wrap:wrap;margin-top:8px;padding-top:8px;border-top:1px dashed var(--border);font-size:11px;color:var(--muted)">';
    extraHtml+='<span>🛣️ '+Math.round(d.distance)+' km</span>';
    extraHtml+='<span>⏱️ '+Math.round(d.driveMin)+' min driving</span>';
    if(!isCrewMode){
      extraHtml+='<span>💤 '+Math.round(d.idleMin)+' min idle</span>';
      extraHtml+='<span>🅿️ '+Math.round(d.stopMin)+' min stopped</span>';
      if(d.efficiencyAvg!==undefined) extraHtml+='<span>⚡ Efficiency: '+d.efficiencyAvg+'</span>';
    }
    extraHtml+='<span>📅 '+d.days+' day'+(d.days!==1?'s':'')+'</span>';
    extraHtml+='</div>';

    return '<div style="border:1px solid var(--border);border-radius:12px;margin-bottom:10px;background:var(--surface2);overflow:hidden;transition:box-shadow .15s" onmouseover="this.style.boxShadow=\'0 2px 12px rgba(34,197,94,.08)\'" onmouseout="this.style.boxShadow=\'none\'">'
      +'<div style="display:flex;align-items:center;gap:12px;padding:12px 16px">'
        +'<div style="font-size:22px;flex-shrink:0;width:30px;text-align:center">'+medal+'</div>'
        +'<div style="flex:1;min-width:0">'
          +'<div style="font-weight:700;font-size:15px;display:flex;align-items:center;gap:6px">'+dotHtml+d.name+'</div>'
          +'<div style="font-size:11px;color:var(--muted);margin-top:1px">'+Math.round(d.distance)+' km · '+d.days+' day'+(d.days!==1?'s':'')+(d.driveMin?' · '+Math.round(d.driveMin)+' min driving':'')+'</div>'
        +'</div>'
        +'<div style="text-align:center;flex-shrink:0">'
          +'<div style="font-family:\'Bebas Neue\',sans-serif;font-size:38px;color:'+safeColor+';line-height:1">'+d.avgSafety+'</div>'
          +'<div style="font-size:8px;color:var(--muted);text-transform:uppercase;letter-spacing:.5px;font-weight:600">Safety Score</div>'
        +'</div>'
      +'</div>'
      +'<div style="padding:6px 16px 12px 58px;border-top:1px solid var(--border);background:rgba(0,0,0,.01)">'
        +evtHtml
        +leaderboardCleanBadge(d.totalEvents)
        +extraHtml
      +'</div>'
    +'</div>';
  }).join('');
}

// ── Shared aggregation helper ──
function aggregateLbRows(rows,isCrewMode){
  var byEntity={};
  rows.forEach(function(r){
    var key=isCrewMode?r.crew_member_id:r.vid;
    if(!byEntity[key]) byEntity[key]={id:key,name:'',days:0,safety:0,harshBrake:0,harshAccel:0,speeding:0,seatbelt:0,cornering:0,distance:0,driveMin:0,idleMin:0,stopMin:0,efficiency:0};
    var d=byEntity[key];
    d.days++;
    d.safety+=Number(r.safety_score);
    d.harshBrake+=(r.harsh_braking||0);d.harshAccel+=(r.harsh_accel||0);d.speeding+=(r.speeding_events||0);d.seatbelt+=(r.seatbelt_off||0);d.cornering+=(r.cornering_events||0);
    d.distance+=Number(r.distance_km||0);d.driveMin+=(r.drive_minutes||0);d.idleMin+=(r.idle_minutes||0);d.stopMin+=(r.stop_minutes||0);
    d.efficiency+=Number(r.efficiency_score||0);
    if(isCrewMode){
      d.name=(crewMembers.find(function(c){return c.id===key;})||{}).name||'Unknown';
    } else {
      d.name=(vehicles.find(function(v){return v.vid===key;})||{}).name||r.driver_name||key;
    }
  });
  return Object.values(byEntity).map(function(d){
    d.avgSafety=d.days?Math.round(d.safety/d.days*10)/10:0;
    d.totalEvents=d.harshBrake+d.harshAccel+d.speeding+d.seatbelt+d.cornering;
    d.efficiencyAvg=d.days?Math.round(d.efficiency/d.days*10)/10:0;
    return d;
  });
}

async function renderDashMaintAlert(){
  var el=document.getElementById('dash-maint-alert');if(!el)return;
  var res=await db.from('maintenance_schedules').select('*,vehicle_odometers(odometer_km)').in('status',['due','overdue']);
  // fallback: just query maintenance_schedules
  var mRes=await db.from('maintenance_schedules').select('*').in('status',['due','overdue']);
  var alerts=mRes.data||[];
  if(!alerts.length){el.style.display='none';return;}
  // match to vehicle names
  var vehMap={};vehicles.forEach(function(v){vehMap[v.vid]=v.name;});
  var html='<div style="font-weight:700;margin-bottom:6px">🔧 Maintenance Alerts</div>';
  html+=alerts.map(function(a){
    var icon=a.status==='overdue'?'🔴':'🟡';
    var vName=vehMap[a.vid]||a.vid;
    return '<div style="font-size:12px;margin-bottom:2px">'+icon+' <strong>'+vName+'</strong> — '+a.maintenance_type+' is '+(a.status==='overdue'?'<span style="color:#dc3545;font-weight:700">OVERDUE</span>':'<span style="color:#e67e22;font-weight:700">DUE SOON</span>')+(a.next_due_km?' (due at '+a.next_due_km.toLocaleString()+' km)':'')+'</div>';
  }).join('');
  el.innerHTML=html;
  el.style.display='block';
}

// Map a city name to a deterministic color from a 6-color palette (same city → same color)
function _cityColor(city){
  if(!city) return null;
  var palette=[
    {bg:'rgba(34,197,94,.15)',  fg:'#4ade80', bd:'rgba(34,197,94,.4)',  ac:'#22c55e'},
    {bg:'rgba(168,85,247,.15)', fg:'#c084fc', bd:'rgba(168,85,247,.4)', ac:'#a855f7'},
    {bg:'rgba(245,158,11,.15)', fg:'#fbbf24', bd:'rgba(245,158,11,.4)', ac:'#f59e0b'},
    {bg:'rgba(236,72,153,.15)', fg:'#f472b6', bd:'rgba(236,72,153,.4)', ac:'#ec4899'},
    {bg:'rgba(59,130,246,.15)', fg:'#60a5fa', bd:'rgba(59,130,246,.4)', ac:'#3b82f6'},
    {bg:'rgba(20,184,166,.15)', fg:'#2dd4bf', bd:'rgba(20,184,166,.4)', ac:'#14b8a6'}
  ];
  var h=0; for(var i=0;i<city.length;i++) h=((h*31)+city.charCodeAt(i))>>>0;
  return palette[h % palette.length];
}

// Refresh just the Today's Jobs panel for whatever date the picker is on
async function refreshDashJobs(){
  var dp = document.getElementById('dash-bin-date');
  var dateS = dp && dp.value ? dp.value : todayStr();
  var realTodayS = todayStr();
  var isToday = dateS === realTodayS;

  // Update the section header label
  var wHdr = document.getElementById('workload-header');
  var dateLbl = isToday ? "TODAY'S JOBS" : "JOBS — " + new Date(dateS+'T12:00:00').toLocaleDateString('en-US',{weekday:'short',month:'short',day:'numeric'}).toUpperCase();
  if(wHdr) wHdr.textContent = '📍 ' + dateLbl;

  // Fetch jobs for the selected date
  // Furniture uses fb_date, Junk uses junk_date, Bin Rental uses bin_dropoff/bin_pickup, others use date
  var [rJobs, rPickups, rDropoffs, rFurn, rJunk] = await Promise.all([
    db.from('jobs').select('*').eq('date', dateS).neq('status','Cancelled').order('time'),
    db.from('jobs').select('*').eq('service','Bin Rental').eq('bin_pickup', dateS).neq('status','Cancelled'),
    db.from('jobs').select('*').eq('service','Bin Rental').neq('status','Cancelled').or('bin_dropoff.eq.'+dateS+',and(bin_dropoff.is.null,date.eq.'+dateS+')'),
    db.from('jobs').select('*').in('service',['Furniture Pickup','Furniture Delivery']).neq('status','Cancelled').or('fb_date.eq.'+dateS+',and(fb_date.is.null,date.eq.'+dateS+')'),
    db.from('jobs').select('*').in('service',['Junk Removal','Junk Quote']).neq('status','Cancelled').or('junk_date.eq.'+dateS+',and(junk_date.is.null,date.eq.'+dateS+')')
  ]);

  var dayJobs      = (rJobs.data||[]).map(dbToJob);
  var dayPickups   = (rPickups.data||[]).map(dbToJob);
  var dayDropoffs  = (rDropoffs.data||[]).map(dbToJob);
  var dayFurn      = (rFurn.data||[]).map(dbToJob);
  var dayJunk      = (rJunk.data||[]).map(dbToJob);

  // Cache in local jobs array
  dayJobs.concat(dayPickups).concat(dayDropoffs).concat(dayFurn).concat(dayJunk).forEach(function(j){
    if(!jobs.find(function(x){return x.id===j.id;})) jobs.push(j);
  });

  function dedup(arr){ var seen={}; return arr.filter(function(j){ if(seen[j.id])return false; seen[j.id]=true; return true; }); }
  dayDropoffs = dedup(dayDropoffs);
  dayPickups  = dedup(dayPickups);
  // Fix same-day misclassification: if a job has no explicit bin_dropoff but has
  // bin_pickup set to this day, it appeared in dropoffs via the date fallback — remove it
  dayDropoffs = dayDropoffs.filter(function(j){
    if(!j.binDropoff && j.binPickup === dateS) return false;
    return true;
  });

  // Use fb_date/junk_date queries for furniture and junk categories
  var furnPickups  = dedup(dayFurn.filter(function(j){return j.service==='Furniture Pickup';}));
  var furnDelivs   = dedup(dayFurn.filter(function(j){return j.service==='Furniture Delivery';}));
  var junkRemovals = dedup(dayJunk.filter(function(j){return j.service==='Junk Removal';}));
  var junkQuotes   = dedup(dayJunk.filter(function(j){return j.service==='Junk Quote';}));

  var allDay = dedup(dayDropoffs.concat(dayPickups).concat(junkRemovals).concat(junkQuotes).concat(furnPickups).concat(furnDelivs));
  var total = allDay.length;
  var unconf = allDay.filter(function(j){return !j.confirmed;}).length;

  // Update count subheading
  var countEl = document.getElementById('dash-today-count');
  if(countEl){
    var parts=[];
    if(dayDropoffs.length) parts.push(dayDropoffs.length+' bin drop'+(dayDropoffs.length!==1?'s':''));
    if(dayPickups.length)  parts.push(dayPickups.length+' pickup'+(dayPickups.length!==1?'s':''));
    if(junkRemovals.length)parts.push(junkRemovals.length+' junk');
    if(furnPickups.length+furnDelivs.length) parts.push((furnPickups.length+furnDelivs.length)+' furniture');
    if(unconf>0) parts.push('<span style="color:#e67e22;font-weight:600">'+unconf+' unconfirmed 📞</span>');
    countEl.innerHTML = parts.join(' · ') || 'Nothing booked';
  }

  // Update stat pill
  var statToday = document.getElementById('dash-stat-today');
  if(statToday) statToday.textContent = total;

  // Urgency state
  var card = document.getElementById('card-today-jobs');
  if(card) card.className = 'chart-card urgency-neutral';

  // Render job rows — column-aligned grid layout
  function makeCat(title,color,list,isPickup){
    if(!list.length)return '';
    var showConfirm = isPickup || title.indexOf('Furniture')>=0;
    // Sort fixed-time rows to the top of the category
    list = list.slice().sort(function(a,b){
      function getTm(j){
        if(j.service==='Bin Rental') return (isPickup ? j.binPickupTime : j.binDropoffTime) || '';
        if(j.service==='Furniture Delivery'||j.service==='Furniture Pickup') return j.fbTime||'';
        if(j.service==='Junk Removal'||j.service==='Junk Quote') return j.junkTime||'';
        return '';
      }
      var ta=getTm(a), tb=getTm(b);
      if(ta && !tb) return -1;
      if(!ta && tb) return 1;
      if(ta && tb) return ta.localeCompare(tb);
      return 0;
    });
    return '<div style="margin-bottom:4px">'
      +'<div style="font-family:Bebas Neue,sans-serif;font-size:20px;letter-spacing:1.5px;color:'+color+';padding:8px 14px 4px">'+title+' <span style="font-family:Inter,sans-serif;font-size:11px;font-weight:700;background:rgba(0,0,0,.06);border-radius:10px;padding:1px 8px">'+list.length+'</span></div>'
      +list.map(function(j){
        var cfm=j.confirmed;
        var legAssignedBin = j.binBid ? binItems.find(function(b){return b.bid===j.binBid;}) : null;
        var binBadge='<span></span>';
        if(legAssignedBin){
          var sz=(j.binSize||'').replace(/\s*yard/i,' YD').toUpperCase();
          binBadge='<span style="font-size:13px;font-weight:700;background:rgba(34,197,94,.18);color:#22c55e;border:1px solid rgba(34,197,94,.5);border-radius:6px;padding:5px 12px;text-align:center;white-space:nowrap;letter-spacing:0.4px;text-shadow:0 0 8px rgba(34,197,94,.3)">'+(isPickup?'#'+legAssignedBin.bid:sz+' · #'+legAssignedBin.bid)+'</span>';
        } else if(j.binSize){
          var sz2=j.binSize.replace(/\s*yard/i,' YD').toUpperCase();
          binBadge='<span style="font-size:13px;font-weight:700;background:rgba(230,126,34,.18);color:#e67e22;border:1px dashed rgba(230,126,34,.6);border-radius:6px;padding:5px 12px;text-align:center;white-space:nowrap;letter-spacing:0.4px;text-shadow:0 0 8px rgba(230,126,34,.3)">'+sz2+'</span>';
        }
        var timeStr=(function(){
          var st;
          if(j.service==='Bin Rental') st = isPickup ? j.binPickupTime : j.binDropoffTime;
          else if(j.service==='Furniture Delivery'||j.service==='Furniture Pickup') st = j.fbTime;
          else if(j.service==='Junk Removal'||j.service==='Junk Quote') st = j.junkTime;
          return st ? ft(st) : '';
        })();
        var hasFixedTime = !!timeStr;
        var timeCell = hasFixedTime
          ? '<div style="display:flex;flex-direction:column;gap:2px"><span style="color:'+color+';font-weight:700;font-family:\'Bebas Neue\',sans-serif;font-size:18px;letter-spacing:0.5px;line-height:1;white-space:nowrap">'+timeStr+'</span><span style="font-size:8.5px;font-weight:700;color:'+color+';background:rgba(255,255,255,.04);border:1px solid '+color+';border-radius:3px;padding:1px 5px;text-align:center;letter-spacing:0.5px;align-self:start">FIXED</span></div>'
          : '<span></span>';
        var fullAddr = j.address || '';
        var _cc = _cityColor(j.city);
        var cityChip = (j.city && _cc) ? '<span style="background:'+_cc.bg+';color:'+_cc.fg+';border:1px solid '+_cc.bd+';border-left:3px solid '+_cc.ac+';font-family:\'Bebas Neue\',sans-serif;font-size:16px;padding:4px 12px;border-radius:5px;letter-spacing:1.2px;text-transform:uppercase;white-space:nowrap;line-height:1.2;max-width:100%;overflow:hidden;text-overflow:ellipsis;display:inline-block;box-sizing:border-box">'+j.city+'</span>' : '';
        var nameAddrTitle = (j.name + (fullAddr ? ' · ' + fullAddr : '')).replace(/"/g,'&quot;');
        var nameAddrCell = '<div title="'+nameAddrTitle+'" style="min-width:0;display:flex;align-items:baseline;gap:6px;white-space:nowrap;overflow:hidden"><span style="color:var(--text);font-weight:600;font-size:13px;flex-shrink:0">'+j.name+'</span>'+(fullAddr?'<span style="color:var(--muted);font-weight:400;font-size:11px;overflow:hidden;text-overflow:ellipsis;min-width:0">· '+fullAddr+'</span>':'')+'</div>';
        var actionBtn='';
        if(j.service==='Bin Rental'&&isPickup&&j.binInstatus==='pickedup'){
          actionBtn='<button class="btn btn-ghost btn-sm" onclick="markDropped(\''+j.id+'\');event.stopPropagation()" style="font-size:11px;white-space:nowrap;color:#4ade80;background:rgba(34,197,94,.15);border:1px solid rgba(34,197,94,.45);border-radius:6px;padding:5px 12px;font-weight:700;display:inline-flex;align-items:center;gap:5px;cursor:pointer" title="Click to undo"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>Picked Up</button>';
        } else if(j.service==='Bin Rental'&&isPickup){
          actionBtn='<button class="btn btn-ghost btn-sm" onclick="markPickedUp(\''+j.id+'\',event);event.stopPropagation()" style="font-size:11px;white-space:nowrap;color:#ec4899;border-color:rgba(236,72,153,.4);border-radius:6px;padding:5px 14px;font-weight:700;display:inline-flex;align-items:center;gap:5px;cursor:pointer"><svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round"><path d="M5 12h14M12 5l7 7-7 7"></path></svg>Pick Up</button>'
            +(!cfm?'<button class="btn btn-ghost btn-sm" onclick="confirmJob(\''+j.id+'\',event);event.stopPropagation()" style="font-size:11px;white-space:nowrap;color:#e67e22;border-color:rgba(230,126,34,.3);background:rgba(230,126,34,.07)">📞 Confirm</button>':'');
        } else if((j.service==='Furniture Pickup'||j.service==='Furniture Delivery')&&!cfm){
          actionBtn='<button class="btn btn-ghost btn-sm" onclick="confirmJob(\''+j.id+'\',event);event.stopPropagation()" style="font-size:11px;white-space:nowrap;color:#e67e22;border-color:rgba(230,126,34,.3);background:rgba(230,126,34,.07)">📞 '+(j.service==='Furniture Delivery'?'Confirm Drop-Off':'Confirm Pickup')+'</button>';
        }
        var assignBtn='';
        if(j.service==='Bin Rental'&&!j.binBid){
          assignBtn='<button class="btn btn-ghost btn-sm" onclick="openAssignBinPicker(\''+j.id+'\');event.stopPropagation()" style="font-size:11px;color:#e67e22;border-color:rgba(230,126,34,.4);white-space:nowrap">📦 Assign</button>';
        }
        var confirmedPill = (showConfirm && cfm && j.service !== 'Bin Rental') ? '<span style="font-size:11px;color:#22c55e;font-weight:600;background:rgba(34,197,94,.1);border-radius:4px;padding:3px 8px">✅</span>' : '';
        var actionsHTML = (assignBtn||actionBtn||confirmedPill)
          ? '<div onclick="event.stopPropagation()" style="display:flex;gap:6px;justify-content:flex-end;align-items:center">'+confirmedPill+assignBtn+actionBtn+'</div>'
          : '<div></div>';
        var rowBg = hasFixedTime
          ? 'background:linear-gradient(90deg,rgba(34,197,94,0.06) 0%,var(--surface2) 30%);border:1px solid rgba(34,197,94,0.4)'
          : 'background:var(--surface2);border:1px solid var(--border)';
        // Pin city + actions widths so city chips align in a vertical column. Time slot is conditional —
        // without it, name+address (1fr) absorbs the freed 90px so city/actions stay at the same X.
        var gridCols = hasFixedTime ? '60px 90px minmax(0,1fr) 170px 280px' : '60px minmax(0,1fr) 170px 280px';
        var rowOpacity = (j.service==='Bin Rental' && j.binInstatus==='pickedup') ? ';opacity:0.6' : '';
        var crewLeg = (j.service==='Bin Rental') ? (isPickup?'pickup':'dropoff') : null;
        return '<div style="display:grid;grid-template-columns:'+gridCols+';gap:10px;align-items:center;padding:10px;'+rowBg+';border-left:4px solid '+color+';border-radius:0 6px 6px 0;margin:0 8px 4px;cursor:pointer;font-size:12px'+rowOpacity+'" onclick="openDetail(\''+j.id+'\')">'
          +'<div>'+jobCrewAvatarsHTML(j, crewLeg)+'</div>'
          +(hasFixedTime?timeCell:'')
          +nameAddrCell
          +'<div style="justify-self:start;min-width:0;max-width:100%;overflow:hidden">'+cityChip+'</div>'
          +'<div style="display:flex;align-items:center;gap:10px;justify-self:end">'+binBadge+actionsHTML+'</div>'
        +'</div>';
      }).join('')+'</div>';
  }

  var html = makeCat('🚛 Bin Deliveries','#0891b2',dayDropoffs,false)
    +makeCat('🚚 Bin Pickups','#ec4899',dayPickups,true)
    +makeCat('Junk Removals','#eab308',junkRemovals,false)
    +makeCat('📋 Junk Quotes','#0d6efd',junkQuotes,false)
    +makeCat('🛋️ Furniture Pickups','#8b5cf6',furnPickups,false)
    +makeCat('📦 Furniture Deliveries','#f97316',furnDelivs,false);

  document.getElementById('dash-today-jobs').innerHTML = html
    || '<div style="color:var(--muted);font-size:13px;padding:12px;text-align:center">No jobs on this date</div>';
}
async function renderWeekCal(){
  if(!document.getElementById('week-cal-grid')) return;
  var ws=getWeekStart(weekOffset),we=new Date(ws);we.setDate(we.getDate()+6);
  var today=new Date();today.setHours(0,0,0,0);
  var wsS=ws.toISOString().split('T')[0];
  var weS=we.toISOString().split('T')[0];
  var opts={month:'short',day:'numeric'};
  document.getElementById('week-lbl').textContent=ws.toLocaleDateString('en-US',opts)+' – '+we.toLocaleDateString('en-US',opts);

  // Fetch this week's jobs: by job date, bin_dropoff, bin_pickup, fb_date, or junk_date falling in this week
  var rByDate = db.from('jobs').select(JOB_LIST_COLS).gte('date',wsS).lte('date',weS).neq('status','Cancelled').order('time');
  var rByDropoff = db.from('jobs').select(JOB_LIST_COLS).eq('service','Bin Rental').gte('bin_dropoff',wsS).lte('bin_dropoff',weS).neq('status','Cancelled');
  var rByPickup = db.from('jobs').select(JOB_LIST_COLS).eq('service','Bin Rental').gte('bin_pickup',wsS).lte('bin_pickup',weS).neq('status','Cancelled');
  var rByFbDate = db.from('jobs').select(JOB_LIST_COLS).in('service',['Furniture Pickup','Furniture Delivery']).gte('fb_date',wsS).lte('fb_date',weS).neq('status','Cancelled');
  var rByJunkDate = db.from('jobs').select(JOB_LIST_COLS).in('service',['Junk Removal','Junk Quote']).gte('junk_date',wsS).lte('junk_date',weS).neq('status','Cancelled');
  var results = await Promise.all([rByDate, rByDropoff, rByPickup, rByFbDate, rByJunkDate]);
  var seen = {};
  var weekJobs = [];
  (results[0].data||[]).concat(results[1].data||[]).concat(results[2].data||[]).concat(results[3].data||[]).concat(results[4].data||[]).forEach(function(row){
    if(!seen[row.id]){ seen[row.id]=true; weekJobs.push(dbToJob(row)); }
  });
  // Cache in local jobs array
  weekJobs.forEach(function(j){ if(!jobs.find(function(x){return x.id===j.id;})) jobs.push(j); });

  // Build event lookup: date -> [{j, type}] matching full calendar logic
  var weekEvents = {};
  weekJobs.forEach(function(j){
    if(j.service==='Bin Rental'){
      var dropDs = j.binDropoff || j.date;
      if(dropDs){ if(!weekEvents[dropDs]) weekEvents[dropDs]=[]; weekEvents[dropDs].push({j:j, type:'dropoff'}); }
      if(j.binPickup && j.binPickup !== dropDs){ if(!weekEvents[j.binPickup]) weekEvents[j.binPickup]=[]; weekEvents[j.binPickup].push({j:j, type:'pickup'}); }
    } else {
      var schedDs = jobSchedDate(j); if(schedDs){ if(!weekEvents[schedDs]) weekEvents[schedDs]=[]; weekEvents[schedDs].push({j:j, type:'job'}); }
    }
  });

  var dayNames=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  var clsMap={'Bin Rental':'svc-bin','Junk Removal':'svc-junk','Junk Quote':'svc-quote','Furniture Pickup':'svc-furn','Furniture Delivery':'svc-furn-del'};
  var hours=[];for(var h=8;h<=17;h++)hours.push(h);

  function evTime(ev){
    if(ev.type==='dropoff') return ev.j.binDropoffTime||'';
    if(ev.type==='pickup')  return ev.j.binPickupTime||'';
    return ev.j.time||'';
  }
  function chipHtml(ev){
    var j=ev.j;var cfmCls=j.confirmed?' confirmed':' unconfirmed';
    var icon='', label=j.name;
    if(ev.type==='pickup'){ icon='🚚 '; }
    else if(ev.type==='dropoff'){ icon='🚛 '; }
    else { var iconMap={'Junk Removal':'🗑️ ','Junk Quote':'📋 ','Furniture Pickup':'🛋️ ','Furniture Delivery':'📦 '};icon=iconMap[j.service]||''; }
    var chipCls = ev.type==='pickup' ? 'svc-pickup' : (clsMap[j.service]||'');
    var titleStr=(ev.type==='pickup'?'Bin Pickup':ev.type==='dropoff'?'Bin Drop-off':j.service)+' · '+j.name;
    var t=evTime(ev);
    return '<div class="week-job-chip '+chipCls+cfmCls+'" draggable="true" data-jid="'+j.id+'" onclick="event.stopPropagation();openDetail(\''+j.id+'\')" title="'+(j.confirmed?'Confirmed':'Not confirmed')+' · '+titleStr+'">'+(t?ft(t)+' ':'')+icon+label+(j.confirmed?'':' 📞')+'</div>';
  }

  // Build header row
  var html='<div class="week-time-grid">';
  // Header: time label + day names
  html+='<div class="week-time-label" style="border-bottom:2px solid var(--border)"></div>';
  for(var i=0;i<7;i++){
    var d=new Date(ws);d.setDate(d.getDate()+i);
    var isToday=d.getTime()===today.getTime();
    html+='<div class="week-day-hdr-cell'+(isToday?' today':'')+'" data-date="'+d.toISOString().split('T')[0]+'"><div class="week-day-name">'+dayNames[d.getDay()]+'</div><div class="week-day-num">'+d.getDate()+'</div></div>';
  }
  // All-day row
  html+='<div class="week-time-label" style="font-size:10px;color:var(--muted)">All Day</div>';
  for(var i=0;i<7;i++){
    var d=new Date(ws);d.setDate(d.getDate()+i);
    var ds=d.toISOString().split('T')[0];
    var dayEvs=weekEvents[ds]||[];
    var allDayChips=dayEvs.filter(function(ev){
      return !evTime(ev);
    }).map(chipHtml).join('');
    html+='<div class="week-time-cell allday" data-date="'+ds+'">'+allDayChips+'</div>';
  }
  // Hour rows
  for(var hi=0;hi<hours.length;hi++){
    var hr=hours[hi];
    var hrLabel=hr<=12?(hr===12?'12 PM':hr+' AM'):(hr-12)+' PM';
    html+='<div class="week-time-label">'+hrLabel+'</div>';
    for(var i=0;i<7;i++){
      var d=new Date(ws);d.setDate(d.getDate()+i);
      var ds=d.toISOString().split('T')[0];
      var dayEvs=weekEvents[ds]||[];
      var hourChips=dayEvs.filter(function(ev){
        var t=evTime(ev);
        if(!t)return false;
        var jobHr=parseInt(t.split(':')[0]);
        return jobHr===hr;
      }).map(chipHtml).join('');
      html+='<div class="week-time-cell" data-date="'+ds+'" data-hour="'+hr+'">'+hourChips+'</div>';
    }
  }
  html+='</div>';
  var wg=document.getElementById('week-grid');
  wg.innerHTML=html;
  wg.querySelectorAll('.week-job-chip[draggable]').forEach(function(chip){
    chip.addEventListener('dragstart',function(e){dragJobId=chip.getAttribute('data-jid');chip.style.opacity='0.4';e.dataTransfer.effectAllowed='move';});
    chip.addEventListener('dragend',function(){chip.style.opacity='';dragJobId=null;});
  });
  wg.querySelectorAll('.week-time-cell,.week-day-hdr-cell').forEach(function(col){
    col.addEventListener('dragover',function(e){if(dragJobId){e.preventDefault();col.style.background='rgba(34,197,94,.13)';}});
    col.addEventListener('dragleave',function(){col.style.background='';});
    col.addEventListener('drop',function(e){
      e.preventDefault();col.style.background='';
      var newDate=col.getAttribute('data-date');
      if(!dragJobId||!newDate)return;
      var dragJob=jobs.find(function(j){return j.id===dragJobId;});
      if(!dragJob)return;
      var patch={};
      if(dragJob.service==='Furniture Pickup'||dragJob.service==='Furniture Delivery'){patch={fb_date:newDate};dragJob.fbDate=newDate;}
      else if(dragJob.service==='Junk Removal'||dragJob.service==='Junk Quote'){patch={junk_date:newDate};dragJob.junkDate=newDate;}
      else{patch={date:newDate};dragJob.date=newDate;}
      patchJob(dragJobId,patch);toast('Job rescheduled to '+fd(newDate)+'!');renderWeekCal();renderCal();renderDash();
    });
  });
}
function shiftWeek(n){weekOffset+=n;renderWeekCal();}
function goToday(){weekOffset=0;renderWeekCal();}
function makeDashRows(list){
  if(!list.length) return '<tr><td colspan="3" style="text-align:center;padding:14px;color:var(--muted);font-size:13px">No upcoming jobs</td></tr>';
  return list.map(function(j){return '<tr onclick="openDetail(\''+j.id+'\')">'+'<td>'+jid(j.id,j.service)+'</td><td><strong>'+j.name+'</strong></td><td>'+fd(j.date)+'</td></tr>';}).join('');
}
function makeDashRowsFurn(list){
  if(!list.length) return '<tr><td colspan="4" style="text-align:center;padding:14px;color:var(--muted);font-size:13px">No upcoming jobs</td></tr>';
  return list.map(function(j){return '<tr onclick="openDetail(\''+j.id+'\')">'+'<td>'+jid(j.id,j.service)+'</td><td><strong>'+j.name+'</strong></td><td>'+sb(j.service)+'</td><td>'+fd(j.date)+'</td></tr>';}).join('');
}
async function renderDashLongBins(){
  var threshold=parseInt((document.getElementById('dash-days-threshold')||{}).value)||7;
  var cutoff=new Date();cutoff.setDate(cutoff.getDate()-threshold);
  var cutoffS=cutoff.toISOString().split('T')[0];
  // Fetch all dropped bins where dropoff/date is older than threshold
  var rLong=await db.from('jobs').select('*').eq('service','Bin Rental').eq('bin_instatus','dropped').lte('bin_dropoff',cutoffS);
  var longBins=(rLong.data||[]).map(dbToJob);
  // Also catch dropped bins with no bin_dropoff but old job date
  var rLong2=await db.from('jobs').select('*').eq('service','Bin Rental').eq('bin_instatus','dropped').is('bin_dropoff',null).lte('date',cutoffS);
  (rLong2.data||[]).forEach(function(row){var j=dbToJob(row);if(!longBins.find(function(x){return x.id===j.id;}))longBins.push(j);});
  // Merge into local jobs array
  longBins.forEach(function(j){if(!jobs.find(function(x){return x.id===j.id;}))jobs.push(j);});
  document.getElementById('dash-long-bins').innerHTML=longBins.length
    ?longBins.map(function(j){
      var drop=j.binDropoff||j.date;
      var days=Math.floor((Date.now()-new Date(drop).getTime())/86400000);
      var urgColor=days>=14?'#dc3545':'#e67e22';
      return'<div style="padding:8px 10px;border:1px solid rgba(230,126,34,.3);border-radius:8px;margin-bottom:8px;background:rgba(230,126,34,.04);display:flex;align-items:center;gap:8px;">'
        +'<div style="flex:1;cursor:pointer" onclick="openDetail(\''+j.id+'\')">'
        +'<div style="display:flex;align-items:center;gap:8px;">'
        +'<strong>'+j.name+'</strong>'
        +'<span style="color:'+urgColor+';font-size:12px;font-weight:700;margin-left:auto">'+days+' days out</span>'
        +'</div>'
        +'<div style="font-size:12px;color:var(--muted);margin-top:1px;">'+(j.binSize||'')+(j.binPickup?' · Pickup: '+fd(j.binPickup):' · No pickup date set')+(j.phone?'<span style="margin-left:8px;font-weight:600;color:var(--text)">'+j.phone+'</span>':'')+'</div>'
        +'</div>'
        +'<button class="btn btn-ghost btn-sm" onclick="markPickedUp(\''+j.id+'\',event)" style="font-size:11px;white-space:nowrap">✅ Picked Up</button>'
        +'</div>';
    }).join('')
    :emptyStateHTML('🟢','All On Schedule','No bins have been out longer than expected.');
}
async function renderDash(){
  // ── Skeleton loading: show placeholders while data loads (v18) ──
  var skTodayJobs=document.getElementById('dash-today-jobs');
  if(skTodayJobs) skTodayJobs.innerHTML=skeletonRows(4);
  var skOverdue=document.getElementById('dash-overdue');
  if(skOverdue) skOverdue.innerHTML=skeletonRows(2);
  var skBinsOut=document.getElementById('dash-bins-out-list');
  if(skBinsOut) skBinsOut.innerHTML=skeletonRows(3);
  var skCallback=document.getElementById('dash-callback-list');
  if(skCallback) skCallback.innerHTML=skeletonRows(3);
  var skBinSize=document.getElementById('dash-bin-by-size');
  if(skBinSize) skBinSize.innerHTML=skeletonCards(4);

  // Re-trigger entrance animations
  document.querySelectorAll('#view-dashboard .dash-section').forEach(function(el){
    el.style.animation='none'; el.style.opacity='0';
    requestAnimationFrame(function(){ el.style.animation=''; });
  });

  // Scroll to top so dashboard content is visible after loading screen
  var mainEl=document.getElementById('main');if(mainEl)mainEl.scrollTop=0;

  var todayS = todayStr();
  var now = new Date();
  // Use ymdLocal (local-time formatter) instead of toISOString() which returns UTC.
  var tomorrowD = new Date(now); tomorrowD.setDate(tomorrowD.getDate()+1);
  var tomorrowS = ymdLocal(tomorrowD);
  var weekStart = new Date(now); weekStart.setDate(now.getDate()-now.getDay());
  var weekStartS = ymdLocal(weekStart);
  var cutoff14 = new Date(now); cutoff14.setDate(now.getDate()+14);
  var cutoff14S = ymdLocal(cutoff14);
  var monthStart = ymdLocal(new Date(now.getFullYear(),now.getMonth(),1));
  // Last week date range for trend badges
  var lastWeekStart = new Date(weekStart); lastWeekStart.setDate(lastWeekStart.getDate()-7);
  var lastWeekStartS = ymdLocal(lastWeekStart);
  var lastWeekEnd = new Date(weekStart); lastWeekEnd.setDate(lastWeekEnd.getDate()-1);
  var lastWeekEndS = ymdLocal(lastWeekEnd);
  // Same day last week
  var sameDayLastWeek = new Date(now); sameDayLastWeek.setDate(sameDayLastWeek.getDate()-7);
  var sameDayLastWeekS = ymdLocal(sameDayLastWeek);

  var datePicker = document.getElementById('dash-bin-date');
  // Preserve user's chosen date across re-renders (e.g. realtime refresh after
  // crew assignment). Only seed today's date if the picker has no value yet.
  if(!datePicker.value) datePicker.value = todayS;
  updateDashDateLabel();
  document.getElementById('today-lbl').textContent = now.toLocaleDateString('en-US',{weekday:'long',year:'numeric',month:'long',day:'numeric'});

  // Parallel Supabase fetches
  var [
    rTotal, rActive, rDone, rUnpaid, rMonthRev,
    rTodayJobs, rWeekJobs, rWeekRev,
    rBinCounts, rJunkCount, rFurnCount,
    rOutstanding, rOverdue, rBinPickupsToday, rBinDropoffsToday,
    rTomorrowJobs, rUnconfirmed14,
    rTodayFurn, rTodayJunk,
    rLastWeekJobs, rLastWeekRev, rSameDayLastWeek
  ] = await Promise.all([
    db.from('jobs').select('*',{count:'exact',head:true}),
    db.from('jobs').select('*',{count:'exact',head:true}).neq('status','Cancelled'),
    db.from('jobs').select('*',{count:'exact',head:true}).eq('status','Cancelled'),
    db.from('jobs').select('*',{count:'exact',head:true}).neq('paid','Paid').neq('status','Cancelled'),
    db.from('jobs').select('price').gte('date',monthStart).neq('status','Cancelled'),
    db.from('jobs').select('*').eq('date',todayS).neq('status','Cancelled').order('time'),
    db.from('jobs').select('*',{count:'exact',head:true}).gte('date',weekStartS).neq('status','Cancelled'),
    db.from('jobs').select('price').gte('date',weekStartS).neq('status','Cancelled'),
    db.from('jobs').select('bin_instatus,bin_size').eq('service','Bin Rental').eq('bin_instatus','dropped'),
    db.from('jobs').select('*',{count:'exact',head:true}).eq('service','Junk Removal').gte('date',monthStart),
    db.from('jobs').select('*',{count:'exact',head:true}).in('service',['Furniture Pickup','Furniture Delivery']).gte('date',monthStart),
    db.from('jobs').select('price').neq('paid','Paid').neq('status','Cancelled'),
    db.from('jobs').select('*').eq('service','Bin Rental').eq('bin_instatus','dropped').neq('status','Cancelled').or('bin_pickup.lt.'+todayS+',bin_pickup.is.null'),
    db.from('jobs').select('*').eq('service','Bin Rental').eq('bin_pickup',todayS).neq('status','Cancelled'),
    db.from('jobs').select('*').eq('service','Bin Rental').neq('status','Cancelled').or('bin_dropoff.eq.'+todayS+',and(bin_dropoff.is.null,date.eq.'+todayS+')'),
    // Tomorrow's jobs
    db.from('jobs').select('*').eq('date',tomorrowS).neq('status','Cancelled').order('time'),
    // Bin Rentals with upcoming pickup + Furniture jobs with upcoming date — unconfirmed (for call-back list)
    db.from('jobs').select('*').in('service',['Bin Rental','Furniture Pickup','Furniture Delivery']).gte('date',todayS).lte('date',cutoff14S).neq('status','Cancelled').eq('confirmed',false).order('date').order('time'),
    // Furniture/junk by their scheduled dates for today
    db.from('jobs').select('*').in('service',['Furniture Pickup','Furniture Delivery']).neq('status','Cancelled').or('fb_date.eq.'+todayS+',and(fb_date.is.null,date.eq.'+todayS+')'),
    db.from('jobs').select('*').in('service',['Junk Removal','Junk Quote']).neq('status','Cancelled').or('junk_date.eq.'+todayS+',and(junk_date.is.null,date.eq.'+todayS+')'),
    // Trend comparisons (v18)
    db.from('jobs').select('*',{count:'exact',head:true}).gte('date',lastWeekStartS).lte('date',lastWeekEndS).neq('status','Cancelled'),
    db.from('jobs').select('price').gte('date',lastWeekStartS).lte('date',lastWeekEndS).neq('status','Cancelled'),
    db.from('jobs').select('*',{count:'exact',head:true}).eq('date',sameDayLastWeekS).neq('status','Cancelled')
  ]);

  // Write hidden stat IDs that other code may reference
  var total      = rTotal.count||0;
  var active     = rActive.count||0;
  var done       = rDone.count||0; // now holds cancelled count
  var unpaidCount= rUnpaid.count||0;
  var monthRev   = (rMonthRev.data||[]).reduce(function(s,r){return s+(parseFloat(r.price)||0);},0);
  var weekJobs   = rWeekJobs.count||0;
  var weekRev    = (rWeekRev.data||[]).reduce(function(s,r){return s+(parseFloat(r.price)||0);},0);
  var outstanding= (rOutstanding.data||[]).reduce(function(s,r){return s+(parseFloat(r.price)||0);},0);
  animCount(document.getElementById('s-total'),total,'','',700);
  animCount(document.getElementById('s-active'),active,'','',700);
  animCount(document.getElementById('s-done'),done,'','',700);
  animCount(document.getElementById('s-unpaid'),unpaidCount,'','',700);
  animCount(document.getElementById('s-month-rev'),Math.round(monthRev),'$','',700);
  document.getElementById('m-active').textContent=weekJobs;
  var wjEl=document.getElementById('s-week-jobs');if(wjEl)animCount(wjEl,weekJobs);
  var wrEl=document.getElementById('s-week-rev');if(wrEl)animCount(wrEl,Math.round(weekRev),'$');
  var osEl=document.getElementById('s-outstanding');if(osEl)animCount(osEl,Math.round(outstanding),'$');

  // ── Trend badges (v18) ────────────────────────────────────
  var lastWeekJobCount = rLastWeekJobs.count||0;
  var lastWeekRevTotal = (rLastWeekRev.data||[]).reduce(function(s,r){return s+(parseFloat(r.price)||0);},0);
  var sameDayLastWeekCount = rSameDayLastWeek.count||0;

  function trendBadge(current, previous, invert){
    if(!previous) return '<span class="trend-badge trend-neutral">—</span>';
    var diff = current - previous;
    var pct = Math.round(Math.abs(diff)/previous*100);
    if(diff===0) return '<span class="trend-badge trend-neutral">→ 0%</span>';
    var up = diff>0;
    var cls = invert ? (up?'trend-up-bad':'trend-down-good') : (up?'trend-up':'trend-down-bad');
    var arrow = up ? '▲' : '▼';
    return '<span class="trend-badge '+cls+'"><span style="font-size:10px">'+arrow+'</span> '+pct+'%</span>';
  }

  // Inject trend into week-jobs stat if element exists
  if(wjEl){
    var wjParent=wjEl.parentElement;
    var existingTrend=wjParent.querySelector('.trend-badge');
    if(existingTrend)existingTrend.remove();
    wjEl.insertAdjacentHTML('afterend','<div style="margin-top:4px">'+trendBadge(weekJobs,lastWeekJobCount)+'<span class="stat-compare-text" style="margin-left:6px">vs '+lastWeekJobCount+' last wk</span></div>');
  }
  if(wrEl){
    var wrParent=wrEl.parentElement;
    var existingTrend2=wrParent.querySelector('.trend-badge');
    if(existingTrend2)existingTrend2.parentElement.remove();
    wrEl.insertAdjacentHTML('afterend','<div style="margin-top:4px">'+trendBadge(Math.round(weekRev),Math.round(lastWeekRevTotal))+'<span class="stat-compare-text" style="margin-left:6px">vs $'+Math.round(lastWeekRevTotal).toLocaleString()+' last wk</span></div>');
  }

  // Bin stats (delegated)
  refreshDashBinStats();
  renderDashVehicleStatus();
  renderDashMaintAlert();

  // ── Today's jobs ──────────────────────────────────────────
  var todayJobs        = (rTodayJobs.data||[]).map(dbToJob);
  var todayBinPickups  = (rBinPickupsToday.data||[]).map(dbToJob);
  var todayBinDropoffs = (rBinDropoffsToday.data||[]).map(dbToJob);

  var allTodayJobs = todayJobs.concat(todayBinPickups).concat(todayBinDropoffs);
  allTodayJobs.forEach(function(j){ if(!jobs.find(function(x){return x.id===j.id;})) jobs.push(j); });

  function dedup(arr){ var seen={}; return arr.filter(function(j){ if(seen[j.id])return false; seen[j.id]=true; return true; }); }
  todayBinDropoffs = dedup(todayBinDropoffs);
  todayBinPickups  = dedup(todayBinPickups);
  // Fix same-day misclassification: if a job has no explicit bin_dropoff but has
  // bin_pickup set to today, it appeared in dropoffs via the date fallback — remove it
  todayBinDropoffs = todayBinDropoffs.filter(function(j){
    if(!j.binDropoff && j.binPickup === todayS) return false;
    return true;
  });

  // Use dedicated fb_date/junk_date queries for furniture and junk (not created date)
  var todayFurnAll      = (rTodayFurn.data||[]).map(dbToJob);
  var todayJunkAll      = (rTodayJunk.data||[]).map(dbToJob);
  todayFurnAll.concat(todayJunkAll).forEach(function(j){ if(!jobs.find(function(x){return x.id===j.id;})) jobs.push(j); });
  var todayJunkRemovals = dedup(todayJunkAll.filter(function(j){return j.service==='Junk Removal';}));
  var todayJunkQuotes   = dedup(todayJunkAll.filter(function(j){return j.service==='Junk Quote';}));
  var todayFurnPickups  = dedup(todayFurnAll.filter(function(j){return j.service==='Furniture Pickup';}));
  var todayFurnDelivs   = dedup(todayFurnAll.filter(function(j){return j.service==='Furniture Delivery';}));

  var allToday = dedup(todayBinDropoffs.concat(todayBinPickups).concat(todayJunkRemovals).concat(todayJunkQuotes).concat(todayFurnPickups).concat(todayFurnDelivs));
  var totalTodayCount = allToday.length;
  var unconfirmedToday = allToday.filter(function(j){return (j.service==='Bin Rental'||j.service==='Furniture Pickup'||j.service==='Furniture Delivery')&&!j.confirmed;}).length;

  // ── QUICK STAT PILLS ──────────────────────────────────────
  var statToday = document.getElementById('dash-stat-today');
  if(statToday) statToday.textContent = totalTodayCount;

  var statUnconf = document.getElementById('dash-stat-unconf');
  if(statUnconf) statUnconf.textContent = unconfirmedToday;
  var statUnconfCard = document.getElementById('dash-stat-unconf-card');
  if(statUnconfCard) statUnconfCard.style.borderLeft = unconfirmedToday > 0 ? '4px solid #e67e22' : '';

  var overdueJobs = (rOverdue.data||[]).map(dbToJob);
  overdueJobs.forEach(function(j){ if(!jobs.find(function(x){return x.id===j.id;})) jobs.push(j); });
  var statOverdue = document.getElementById('dash-stat-overdue');
  if(statOverdue) statOverdue.textContent = overdueJobs.length;
  var statOverdueCard = document.getElementById('dash-stat-overdue-card');
  if(statOverdueCard) statOverdueCard.style.borderLeft = overdueJobs.length > 0 ? '4px solid #dc3545' : '';

  // ── TOMORROW PILL in header ───────────────────────────────
  var tomorrowJobs = (rTomorrowJobs.data||[]).map(dbToJob);
  var tomorrowUnconf = tomorrowJobs.filter(function(j){return (j.service==='Bin Rental'||j.service==='Furniture Pickup'||j.service==='Furniture Delivery')&&!j.confirmed;}).length;
  var tPill = document.getElementById('dash-tomorrow-pill');
  if(tPill && tomorrowJobs.length > 0){
    tPill.style.display = '';
    tPill.innerHTML = 'Tomorrow: <strong style="color:var(--text)">' + tomorrowJobs.length + ' job' + (tomorrowJobs.length!==1?'s':'') + '</strong>'
      + (tomorrowUnconf > 0 ? ' &nbsp;·&nbsp; <span style="color:#e67e22;font-weight:600">' + tomorrowUnconf + ' pickup unconfirmed</span>' : '');
  } else if(tPill){
    tPill.style.display = 'none';
  }

  // ── WORKLOAD HEADER ───────────────────────────────────────
  var workloadHdr = document.getElementById('workload-header');
  if(workloadHdr){
    var wLabel;
    if(!totalTodayCount){ wLabel='📍 FREE DAY'; }
    else if(totalTodayCount===1){ wLabel='📍 TODAY — 1 JOB'; }
    else if(totalTodayCount<=3){ wLabel='📍 LIGHT DAY — '+totalTodayCount+' JOBS'; }
    else if(totalTodayCount<=5){ wLabel='📍 BUSY — '+totalTodayCount+' JOBS'; }
    else { wLabel='📍 HEAVY DAY — '+totalTodayCount+' JOBS'; }
    workloadHdr.innerHTML = wLabel;
  }

  // Count line for sub-header — render as color-coded pill chips so it matches the
  // tinted job rows below and is scannable at a glance on heavy days.
  var countEl = document.getElementById('dash-today-count');
  if(countEl){
    function _countChip(rgbCsv, color, icon, count, label){
      // Neutral pill with colored count number — uses color as accent, not background.
      return '<span style="display:inline-flex;align-items:center;gap:5px;padding:3px 10px;border-radius:99px;background:var(--surface2);color:var(--text-secondary);border:1px solid var(--border);font-size:11px;font-weight:600;line-height:1.5;white-space:nowrap">'+icon+' <strong style="color:'+color+';font-weight:800">'+count+'</strong> '+label+'</span>';
    }
    var chips = [];
    if(todayBinDropoffs.length) chips.push(_countChip('8,145,178','#0891b2','🚛',todayBinDropoffs.length,'drop'+(todayBinDropoffs.length!==1?'s':'')));
    if(todayBinPickups.length)  chips.push(_countChip('236,72,153','#ec4899','🚚',todayBinPickups.length,'pickup'+(todayBinPickups.length!==1?'s':'')));
    if(todayJunkRemovals.length)chips.push(_countChip('234,179,8','#a16207','🗑️',todayJunkRemovals.length,'junk'));
    if(todayJunkQuotes.length)  chips.push(_countChip('13,110,253','#0d6efd','📋',todayJunkQuotes.length,'quote'+(todayJunkQuotes.length!==1?'s':'')));
    var furnTotal = todayFurnPickups.length + todayFurnDelivs.length;
    if(furnTotal)               chips.push(_countChip('139,92,246','#8b5cf6','🛋️',furnTotal,'furniture'));
    if(unconfirmedToday>0)      chips.push(_countChip('230,126,34','#e67e22','📞',unconfirmedToday,'not ready'));
    countEl.innerHTML = chips.length
      ? '<div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:4px">'+chips.join('')+'</div>'
      : '<span style="color:var(--muted)">Nothing booked</span>';
  }

  // Today card urgency
  var todayCard = document.getElementById('card-today-jobs');
  if(todayCard) todayCard.className = 'chart-card urgency-neutral';

  // ── TODAY'S JOBS — full detail, actionable rows ───────────
  function makeTodayCat(title,color,list,showBinActions){
    if(!list.length)return '<div style="margin-bottom:4px"><div style="font-family:Bebas Neue,sans-serif;font-size:20px;letter-spacing:1.5px;color:'+color+';padding:8px 14px 4px">'+title+' <span style="font-family:Inter,sans-serif;font-size:11px;font-weight:700;background:rgba(0,0,0,.06);border-radius:10px;padding:1px 8px">0</span></div><div style="font-size:13px;color:var(--muted);padding:2px 14px 6px;font-style:italic">No jobs today</div></div>';
    var showConfirm = showBinActions || title.indexOf('Furniture')>=0;
    // Sort fixed-time rows to the top
    list = list.slice().sort(function(a,b){
      function getTm(j){
        if(j.service==='Bin Rental') return (showBinActions ? j.binPickupTime : j.binDropoffTime) || '';
        if(j.service==='Furniture Delivery'||j.service==='Furniture Pickup') return j.fbTime||'';
        if(j.service==='Junk Removal'||j.service==='Junk Quote') return j.junkTime||'';
        return '';
      }
      var ta=getTm(a), tb=getTm(b);
      if(ta && !tb) return -1;
      if(!ta && tb) return 1;
      if(ta && tb) return ta.localeCompare(tb);
      return 0;
    });
    return '<div style="margin-bottom:4px">'
      +'<div style="font-family:Bebas Neue,sans-serif;font-size:20px;letter-spacing:1.5px;color:'+color+';padding:8px 14px 4px">'+title+' <span style="font-family:Inter,sans-serif;font-size:11px;font-weight:700;background:rgba(0,0,0,.06);border-radius:10px;padding:1px 8px">'+list.length+'</span></div>'
      +list.map(function(j){
        var cfm = j.confirmed;
        var actionBtn = '';
        if(j.service==='Bin Rental'&&showBinActions&&j.binInstatus==='pickedup'){
          actionBtn = '<button class="btn btn-ghost btn-sm" onclick="markDropped(\''+j.id+'\');event.stopPropagation()" style="font-size:11px;white-space:nowrap;color:#4ade80;background:rgba(34,197,94,.15);border:1px solid rgba(34,197,94,.45);border-radius:6px;padding:5px 12px;font-weight:700;display:inline-flex;align-items:center;gap:5px;cursor:pointer" title="Click to undo"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>Picked Up</button>';
        } else if(j.service==='Bin Rental'&&showBinActions){
          actionBtn = '<button class="btn btn-ghost btn-sm" onclick="markPickedUp(\''+j.id+'\',event);event.stopPropagation()" style="font-size:11px;white-space:nowrap;color:#ec4899;border-color:rgba(236,72,153,.4);border-radius:6px;padding:5px 14px;font-weight:700;display:inline-flex;align-items:center;gap:5px;cursor:pointer"><svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round"><path d="M5 12h14M12 5l7 7-7 7"></path></svg>Pick Up</button>'
            +(!cfm?'<button class="btn btn-ghost btn-sm" onclick="confirmJob(\''+j.id+'\',event);event.stopPropagation()" style="font-size:11px;white-space:nowrap;color:#e67e22;border-color:rgba(230,126,34,.3);background:rgba(230,126,34,.07)">📞 Confirm</button>':'');
        } else if((j.service==='Furniture Pickup'||j.service==='Furniture Delivery')&&!cfm){
          var cfmWord = j.service==='Furniture Delivery'?'Drop-Off':'Pickup';
          actionBtn = '<div class="jdd-wrap" onclick="event.stopPropagation()">'
            +'<button class="jdd-btn" style="border-color:rgba(34,197,94,.3);color:#22c55e;font-size:11px;padding:4px 9px;background:rgba(34,197,94,.07)" onclick="toggleJdd(this.parentElement)">Confirm '+cfmWord+' ▾</button>'
            +'<div class="jdd-menu">'
              +'<div class="jdd-item" onclick="confirmJob(\''+j.id+'\',event)">✅ Mark Confirmed</div>'
              +'<div class="jdd-divider"></div>'
              +'<div class="jdd-item" onclick="openDetail(\''+j.id+'\')">📋 Open Details</div>'
              +(j.phone?'<div class="jdd-item" onclick="window.location=\'tel:\'+j.phone;event.stopPropagation()">📞 '+j.phone+'</div>':'')
            +'</div>'
          +'</div>';
        }
        var todayAssignedBin = j.binBid ? binItems.find(function(b){return b.bid===j.binBid;}) : null;
        var binBadge = '<span></span>';
        if(todayAssignedBin){
          var sz = (j.binSize||'').replace(/\s*yard/i,' YD').toUpperCase();
          binBadge = '<span style="font-size:13px;font-weight:700;background:rgba(34,197,94,.18);color:#22c55e;border:1px solid rgba(34,197,94,.5);border-radius:6px;padding:5px 12px;text-align:center;white-space:nowrap;letter-spacing:0.4px;text-shadow:0 0 8px rgba(34,197,94,.3)">'+(showBinActions?'#'+todayAssignedBin.bid:sz+' · #'+todayAssignedBin.bid)+'</span>';
        } else if(j.binSize){
          var sz2 = j.binSize.replace(/\s*yard/i,' YD').toUpperCase();
          binBadge = '<span style="font-size:13px;font-weight:700;background:rgba(230,126,34,.18);color:#e67e22;border:1px dashed rgba(230,126,34,.6);border-radius:6px;padding:5px 12px;text-align:center;white-space:nowrap;letter-spacing:0.4px;text-shadow:0 0 8px rgba(230,126,34,.3)">'+sz2+'</span>';
        }
        var assignBinBtn = (j.service==='Bin Rental' && !j.binBid)
          ? '<button class="btn btn-ghost btn-sm" onclick="openAssignBinPicker(\''+j.id+'\');event.stopPropagation()" style="font-size:11px;color:#e67e22;border-color:rgba(230,126,34,.4);white-space:nowrap">📦 Assign</button>'
          : '';
        var timeStr = (function(){
          var st;
          if(j.service==='Bin Rental') st = showBinActions ? j.binPickupTime : j.binDropoffTime;
          else if(j.service==='Furniture Delivery'||j.service==='Furniture Pickup') st = j.fbTime;
          else if(j.service==='Junk Removal'||j.service==='Junk Quote') st = j.junkTime;
          return st ? ft(st) : '';
        })();
        var hasFixedTime = !!timeStr;
        var timeCell = hasFixedTime
          ? '<div style="display:flex;flex-direction:column;gap:2px"><span style="color:'+color+';font-weight:700;font-family:\'Bebas Neue\',sans-serif;font-size:18px;letter-spacing:0.5px;line-height:1;white-space:nowrap">'+timeStr+'</span><span style="font-size:8.5px;font-weight:700;color:'+color+';background:rgba(255,255,255,.04);border:1px solid '+color+';border-radius:3px;padding:1px 5px;text-align:center;letter-spacing:0.5px;align-self:start">FIXED</span></div>'
          : '<span></span>';
        var fullAddr = j.address || '';
        var _cc = _cityColor(j.city);
        var cityChip = (j.city && _cc) ? '<span style="background:'+_cc.bg+';color:'+_cc.fg+';border:1px solid '+_cc.bd+';border-left:3px solid '+_cc.ac+';font-family:\'Bebas Neue\',sans-serif;font-size:16px;padding:4px 12px;border-radius:5px;letter-spacing:1.2px;text-transform:uppercase;white-space:nowrap;line-height:1.2;max-width:100%;overflow:hidden;text-overflow:ellipsis;display:inline-block;box-sizing:border-box">'+j.city+'</span>' : '';
        var nameAddrTitle = (j.name + (fullAddr ? ' · ' + fullAddr : '')).replace(/"/g,'&quot;');
        var nameAddrCell = '<div title="'+nameAddrTitle+'" style="min-width:0;display:flex;align-items:baseline;gap:6px;white-space:nowrap;overflow:hidden"><span style="color:var(--text);font-weight:600;font-size:13px;flex-shrink:0">'+j.name+'</span>'+(fullAddr?'<span style="color:var(--muted);font-weight:400;font-size:11px;overflow:hidden;text-overflow:ellipsis;min-width:0">· '+fullAddr+'</span>':'')+'</div>';
        var confirmedPill = (showConfirm && cfm && j.service !== 'Bin Rental') ? '<span style="font-size:11px;color:#22c55e;font-weight:600;background:rgba(34,197,94,.1);border-radius:4px;padding:3px 8px">✅</span>' : '';
        var actionsHTML = (assignBinBtn||actionBtn||confirmedPill)
          ? '<div onclick="event.stopPropagation()" style="display:flex;gap:6px;justify-content:flex-end;align-items:center">'+confirmedPill+assignBinBtn+actionBtn+'</div>'
          : '<div></div>';
        // Neutral row background — color is reserved for the section-color border-left
        // (category accent) and for the shadow on fixed-time rows (status emphasis).
        // This keeps the dashboard calm overall and lets status colors (red/orange) pop.
        var rgbCsv = _hexOrRgbToRgbCsv(color) || '34,197,94';
        var rowBg = hasFixedTime
          ? 'background:var(--surface);border:1px solid var(--border-strong);box-shadow:0 4px 14px rgba('+rgbCsv+',.18)'
          : 'background:var(--surface);border:1px solid var(--border)';
        // Pin city + actions widths so city chips align in a vertical column. Time slot is conditional —
        // without it, name+address (1fr) absorbs the freed 90px so city/actions stay at the same X.
        var gridCols = hasFixedTime ? '60px 90px minmax(0,1fr) 170px 280px' : '60px minmax(0,1fr) 170px 280px';
        var rowOpacity = (j.service==='Bin Rental' && j.binInstatus==='pickedup') ? ';opacity:0.55' : '';
        var crewLeg = (j.service==='Bin Rental') ? (showBinActions?'pickup':'dropoff') : null;
        return '<div style="display:grid;grid-template-columns:'+gridCols+';gap:10px;align-items:center;padding:11px 12px;'+rowBg+';border-left:5px solid '+color+';border-radius:0 8px 8px 0;margin:0 8px 5px;cursor:pointer;font-size:12.5px'+rowOpacity+'" onclick="openDetail(\''+j.id+'\')">'
          +'<div>'+jobCrewAvatarsHTML(j, crewLeg)+'</div>'
          +(hasFixedTime?timeCell:'')
          +nameAddrCell
          +'<div style="justify-self:start;min-width:0;max-width:100%;overflow:hidden">'+cityChip+'</div>'
          +'<div style="display:flex;align-items:center;gap:10px;justify-self:end">'+binBadge+actionsHTML+'</div>'
        +'</div>';
      }).join('')+'</div>';
  }
  var todayHtml = makeTodayCat('🚛 Bin Deliveries','#0891b2',todayBinDropoffs,false)
    +makeTodayCat('🚚 Bin Pickups','#ec4899',todayBinPickups,true)
    +makeTodayCat('Junk Removals','#eab308',todayJunkRemovals,false)
    +makeTodayCat('📋 Junk Quotes','#0d6efd',todayJunkQuotes,false)
    +makeTodayCat('🛋️ Furniture Pickups','#8b5cf6',todayFurnPickups,false)
    +makeTodayCat('📦 Furniture Deliveries','#f97316',todayFurnDelivs,false);
  document.getElementById('dash-today-jobs').innerHTML = todayHtml
    ||emptyStateHTML('📅','No Jobs Today','Nothing scheduled. Hit "+ New Job" to add one.');

  renderWillCallCard();

  // ── CALL-BACK LIST — unconfirmed upcoming jobs ────────────
  var callbackJobs = (rUnconfirmed14.data||[]).map(dbToJob);
  callbackJobs.forEach(function(j){ if(!jobs.find(function(x){return x.id===j.id;})) jobs.push(j); });
  var cbEl = document.getElementById('dash-callback-list');
  if(cbEl){
    if(!callbackJobs.length){
      cbEl.innerHTML=emptyStateHTML('📞','All Confirmed','Every pickup and drop-off is confirmed. Nothing to call about.');
    } else {
      cbEl.innerHTML = callbackJobs.map(function(j){
        var sd = jobSchedDate(j);
        var isToday = sd===todayS;
        var isTom   = sd===tomorrowS;
        var dateLabel = isToday?'<span style="color:#dc3545;font-weight:700">TODAY</span>'
          : isTom?'<span style="color:#e67e22;font-weight:700">Tomorrow</span>'
          : fd(sd);
        var isDelivery = j.service==='Furniture Delivery';
        var cfmLabel = isDelivery?'Drop-Off':'Pickup';
        return '<div style="padding:8px 10px;border:1px solid rgba(230,126,34,.3);border-left:3px solid #e67e22;border-radius:0 8px 8px 0;margin-bottom:6px;background:rgba(230,126,34,.04);">'
          +'<div style="display:flex;align-items:center;gap:8px;">'
            +'<div style="flex:1;min-width:0;cursor:pointer" onclick="openDetail(\''+j.id+'\')">'
              +'<div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">'
                +'<strong style="font-size:13px">'+j.name+'</strong>'
                +dateLabel
                +(j.phone?'<span style="font-size:11px;font-weight:600;color:var(--text)">'+j.phone+'</span>':'')
              +'</div>'
              +'<div style="font-size:11px;color:var(--muted);margin-top:1px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">'+j.id+(j.service?'<span style="margin-left:6px">'+j.service+'</span>':'')+'</div>'
            +'</div>'
            +'<div class="jdd-wrap" style="flex-shrink:0" onclick="event.stopPropagation()">'
              +'<button class="jdd-btn" style="border-color:rgba(34,197,94,.3);color:#22c55e;font-size:11px;padding:4px 9px;background:rgba(34,197,94,.07)" onclick="toggleJdd(this.parentElement)">Confirm '+cfmLabel+' ▾</button>'
              +'<div class="jdd-menu">'
                +'<div class="jdd-item" onclick="confirmJob(\''+j.id+'\',event)">✅ Mark Confirmed</div>'
                +'<div class="jdd-divider"></div>'
                +'<div class="jdd-item" onclick="openDetail(\''+j.id+'\')">📋 Open Details</div>'
                +(j.phone?'<div class="jdd-item" onclick="window.location=\'tel:\'+j.phone;event.stopPropagation()">📞 '+j.phone+'</div>':'')
              +'</div>'
            +'</div>'
          +'</div>'
        +'</div>';
      }).join('');
    }
  }

  // ── OVERDUE PICKUPS ───────────────────────────────────────
  document.getElementById('dash-overdue').innerHTML = overdueJobs.length
    ? overdueJobs.map(function(j){return'<div style="padding:8px 10px;border:1px solid rgba(220,53,69,.3);border-radius:8px;margin-bottom:8px;background:rgba(220,53,69,.04);display:flex;align-items:center;gap:8px;">'
      +'<div style="flex:1;cursor:pointer" onclick="openDetail(\''+j.id+'\')">'
      +'<strong style="color:#dc3545">'+j.name+'</strong>'
      +'<div style="font-size:12px;color:var(--muted);margin-top:1px;">'+(j.binPickup?'Pickup was: '+fd(j.binPickup):'No pickup date set')+(j.binSize?' · '+j.binSize:'')+'</div>'
      +'</div>'
      +'<button class="btn btn-ghost btn-sm" onclick="markPickedUp(\''+j.id+'\',event)" style="font-size:11px;white-space:nowrap">✅ Picked Up</button>'
      +'</div>';}).join('')
    :emptyStateHTML('✅','All Clear!','No overdue pickups right now. Nice work keeping things on track.');

  var overdueCard=document.getElementById('card-overdue');
  if(overdueCard) overdueCard.className='chart-card '+(overdueJobs.length>0?'urgency-warn':'urgency-ok');

  renderDashLongBins();
  renderWeekCal();
  renderDashBinsOut();

  // If the user has the picker on a non-today date (e.g. assigning crew to
  // tomorrow's jobs), the dash-today-jobs panel was just overwritten with
  // today's data above. Re-render it with the picker's date so we don't
  // snap them back.
  if(datePicker.value && datePicker.value !== todayS){
    refreshDashJobs();
  }

  // Keep hidden stub IDs up to date so nothing else breaks
  var upcomingHdrEl=document.getElementById('upcoming-hdr-lbl');
  if(upcomingHdrEl) upcomingHdrEl.textContent='';
}

async function renderWillCallCard(){
  var listEl=document.getElementById('dash-will-call-list');
  var countEl=document.getElementById('dash-will-call-count');
  if(!listEl)return;
  var r=await db.from('jobs').select('*').eq('service','Bin Rental').eq('bin_will_call',true).neq('status','Cancelled').order('bin_pickup');
  var wcJobs=(r.data||[]).map(dbToJob);
  // Merge into local jobs array so action buttons (openDetail, etc.) work
  wcJobs.forEach(function(j){ if(!jobs.find(function(x){return x.id===j.id;})) jobs.push(j); });
  if(countEl) countEl.textContent = wcJobs.length ? (wcJobs.length+' job'+(wcJobs.length===1?'':'s')+' awaiting customer call') : '';
  if(!wcJobs.length){
    listEl.innerHTML='<div style="padding:18px 20px;font-size:13px;color:var(--muted);font-style:italic">No jobs flagged for Will Call.</div>';
    return;
  }
  var iconLoc='<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-2px;margin-right:3px"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>';
  var iconCal='<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>';
  var rows=wcJobs.map(function(j){
    var assignedBin=j.binBid?binItems.find(function(b){return b.bid===j.binBid;}):null;
    var binBadge='';
    if(assignedBin){
      var sz=(j.binSize||'').replace(/\s*yard/i,' YD').toUpperCase();
      binBadge='<span style="font-size:11px;font-weight:600;background:rgba(34,197,94,.1);color:#22c55e;border:1px solid rgba(34,197,94,.3);border-radius:5px;padding:1px 8px;white-space:nowrap;flex-shrink:0">'+sz+' · #'+assignedBin.bid+'</span>';
    } else if(j.binSize){
      var sz2=j.binSize.replace(/\s*yard/i,' YD').toUpperCase();
      binBadge='<span style="font-size:11px;font-weight:600;background:rgba(230,126,34,.1);color:#e67e22;border:1px solid rgba(230,126,34,.3);border-radius:5px;padding:1px 8px;white-space:nowrap;flex-shrink:0">'+sz2+'</span>';
    }
    var addrStr=j.address?j.address.split(',')[0]:'';
    var tentDate=j.binPickup?'<span style="color:var(--muted);font-size:11px;flex-shrink:0">tentative '+fd(j.binPickup)+'</span>':'';
    var schedBtn='<button class="btn btn-ghost btn-sm" onclick="scheduleWillCallPickup(\''+j.id+'\',event);event.stopPropagation()" style="font-size:11px;white-space:nowrap;color:#22c55e;border-color:rgba(34,197,94,.3);background:rgba(34,197,94,.07);flex-shrink:0;display:inline-flex;align-items:center;gap:4px">'+iconCal+' Schedule Pickup</button>';
    return '<div style="padding:8px 10px;border:1px solid var(--border);border-left:4px solid #e67e22;border-radius:0 8px 8px 0;margin:0 8px 4px;background:var(--surface2);cursor:pointer;display:flex;align-items:center;gap:8px;" onclick="openDetail(\''+j.id+'\')">'
      +jobCrewAvatarsHTML(j)
      +'<div style="flex:1;min-width:0;display:flex;align-items:center;gap:6px;overflow:hidden;white-space:nowrap;font-size:12px">'
        +'<span style="flex-shrink:0">'+j.name+'</span>'
        +binBadge
        +(tentDate?'<span style="color:var(--muted);font-size:12px;flex-shrink:0">·</span>'+tentDate:'')
        +(addrStr||j.city?'<span style="color:var(--muted);font-size:12px;flex-shrink:0">·</span><span style="color:var(--muted);font-size:11px;overflow:hidden;text-overflow:ellipsis">'+iconLoc+(addrStr?(addrStr+(j.city?' · '+j.city:'')):j.city)+'</span>':'')
      +'</div>'
      +'<div onclick="event.stopPropagation()" style="display:flex;gap:6px;flex-shrink:0">'+schedBtn+'</div>'
    +'</div>';
  }).join('');
  listEl.innerHTML=rows;
}

async function renderDashBinsOut(){
  var el=document.getElementById('dash-bins-out-list');if(!el)return;
  // Get all active dropped bin rental jobs — these are the bins currently out
  var droppedRes=await db.from('jobs').select('*').eq('service','Bin Rental').eq('bin_instatus','dropped').neq('status','Cancelled').order('bin_dropoff');
  var droppedJobs=(droppedRes.data||[]).map(dbToJob);

  // Split into assigned (has bin) and unassigned (no bin)
  // Unassigned only shows when delivery date is today or has passed — these are "forgot to assign a bin" cases
  var _today=todayStr();
  var assignedJobs=droppedJobs.filter(function(j){return !!j.binBid;});
  var unassignedJobs=droppedJobs.filter(function(j){return !j.binBid && j.binDropoff && j.binDropoff<=_today;});

  if(!assignedJobs.length&&!unassignedJobs.length){el.innerHTML=emptyStateHTML('🏠','All Bins Home','Every bin is back in the yard. Ready for the next job.');return;}

  // Group assigned jobs by size
  var grouped={};
  assignedJobs.forEach(function(j){
    var sz=j.binSize||'Unknown';
    if(!grouped[sz])grouped[sz]=[];
    grouped[sz].push(j);
  });
  var sizeOrder=['4 yard','7 yard','14 yard','20 yard','Unknown'];
  var sizeKeys=Object.keys(grouped).sort(function(a,b){return (sizeOrder.indexOf(a)===-1?99:sizeOrder.indexOf(a))-(sizeOrder.indexOf(b)===-1?99:sizeOrder.indexOf(b));});

  function _daysOutBadge(dropDate){
    if(!dropDate)return '';
    var d0=new Date(dropDate+'T12:00:00'),now=new Date();
    var days=Math.max(0,Math.floor((now-d0)/86400000));
    var bg,color,border;
    if(days>=14){bg='rgba(220,53,69,.15)';color='#dc3545';border='rgba(220,53,69,.4)';}
    else if(days>=7){bg='rgba(230,126,34,.15)';color='#e67e22';border='rgba(230,126,34,.4)';}
    else{bg='rgba(34,197,94,.12)';color='#22c55e';border='rgba(34,197,94,.35)';}
    return '<span style="font-size:11px;font-weight:700;background:'+bg+';color:'+color+';border:1px solid '+border+';border-radius:5px;padding:1px 7px;white-space:nowrap">'+days+' day'+(days!==1?'s':'')+'</span>';
  }
  function renderAssignedCard(j){
    var dropDate=j.binDropoff||j.date;
    var daysBadge=_daysOutBadge(dropDate);
    var pickupBtn='<button class="btn btn-ghost btn-sm" onclick="event.stopPropagation();dashMarkPickedUp(\''+j.id+'\',\''+(j.binBid||'')+'\')" style="font-size:11px;white-space:nowrap;padding:3px 10px;border:1px solid rgba(34,197,94,.3);color:#22c55e;border-radius:6px;margin-left:auto;flex-shrink:0">✅ Picked Up</button>';
    return '<div style="padding:8px 12px;border:1px solid var(--border);border-left:3px solid #dc3545;border-radius:0 8px 8px 0;margin-bottom:5px;background:var(--surface2);cursor:pointer" onclick="openDetail(\''+j.id+'\')">'
      +'<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">'
        +'<span style="font-size:12px;background:rgba(220,53,69,.12);color:#dc3545;border:1px solid rgba(220,53,69,.35);border-radius:5px;padding:1px 7px;font-weight:700">'+j.binBid+'</span>'
        +'<strong style="font-size:13px">'+j.name+'</strong>'
        +daysBadge
        +pickupBtn
      +'</div>'
      +'<div style="font-size:11px;margin-top:3px;display:flex;flex-wrap:wrap;gap:6px;align-items:center">'
        +(j.phone?'<span style="color:#0d6efd;font-weight:600">📞 '+j.phone+'</span>':'')
        +'<span style="color:var(--muted)">📍 '+(j.address||'').split(',')[0]+(j.city?' · '+j.city:'')+'</span>'
        +(j.binPickup?'<span style="color:#9b59b6;font-weight:600">🗓 Pickup: '+fd(j.binPickup)+'</span>':'')
      +'</div>'
    +'</div>';
  }

  function renderUnassignedCard(j){
    var dropDate=j.binDropoff||j.date;
    var daysBadge=_daysOutBadge(dropDate);
    var assignBtn='<button class="btn btn-ghost btn-sm" onclick="event.stopPropagation();openAssignBinPicker(\''+j.id+'\')" style="font-size:11px;white-space:nowrap;padding:3px 10px;border:1px solid rgba(230,126,34,.3);color:#e67e22;border-radius:6px;margin-left:auto;flex-shrink:0">Assign Bin</button>';
    return '<div style="padding:8px 12px;border:1px solid var(--border);border-left:3px solid #e67e22;border-radius:0 8px 8px 0;margin-bottom:5px;background:var(--surface2);cursor:pointer" onclick="openDetail(\''+j.id+'\')">'
      +'<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">'
        +'<strong style="font-size:13px">'+j.name+'</strong>'
        +(j.binSize?'<span style="font-size:11px;font-weight:600;background:rgba(13,110,253,.12);color:#0d6efd;border:1px solid rgba(13,110,253,.3);border-radius:5px;padding:1px 7px">'+j.binSize+'</span>':'')
        +daysBadge
        +assignBtn
      +'</div>'
      +'<div style="font-size:11px;margin-top:3px;display:flex;flex-wrap:wrap;gap:6px;align-items:center">'
        +(j.phone?'<span style="color:#0d6efd;font-weight:600">📞 '+j.phone+'</span>':'')
        +'<span style="color:var(--muted)">📍 '+(j.address||'').split(',')[0]+(j.city?' · '+j.city:'')+'</span>'
      +'</div>'
    +'</div>';
  }

  var html='<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:16px">';
  // Unassigned column first if there are any
  if(unassignedJobs.length){
    html+='<div>'
      +'<div style="font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:#e67e22;margin-bottom:6px;padding-bottom:4px;border-bottom:2px solid #e67e22">No Bin Assigned <span style="font-size:11px;font-weight:600">('+unassignedJobs.length+')</span></div>'
      +unassignedJobs.map(renderUnassignedCard).join('')
    +'</div>';
  }
  // Then size-grouped assigned bins
  html+=sizeKeys.map(function(sz){
    return '<div>'
      +'<div style="font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:var(--muted);margin-bottom:6px;padding-bottom:4px;border-bottom:2px solid var(--border)">'+sz+' <span style="font-size:11px;font-weight:600;color:var(--accent)">('+grouped[sz].length+')</span></div>'
      +grouped[sz].map(renderAssignedCard).join('')
    +'</div>';
  }).join('');
  html+='</div>';
  el.innerHTML=html;
}

// ── CONFIRM JOB quick action ──────────────────────────────
async function confirmJob(id, e){
  if(e)e.stopPropagation();
  var j=jobs.find(function(x){return x.id===id;});
  if(!j)return;
  j.confirmed=true;
  // Immediately remove from callback list DOM — don't wait for DB round-trip
  var cbEl = document.getElementById('dash-callback-list');
  if(cbEl){
    // Find and remove the row containing this job's confirm button
    var rows = cbEl.querySelectorAll('div[style*="border-left"]');
    rows.forEach(function(row){
      if(row.innerHTML.indexOf("confirmJob('"+id+"'") >= 0 || row.innerHTML.indexOf('confirmJob(\''+id+'\'') >= 0){
        row.remove();
      }
    });
    // If no rows left, show the "all confirmed" message
    var remaining = cbEl.querySelectorAll('div[style*="border-left"]');
    if(!remaining.length){
      cbEl.innerHTML=emptyStateHTML('📞','All Confirmed','Every pickup and drop-off is confirmed. Nothing to call about.');
    }
  }
  // Also update the today's jobs section — hide the confirm button for this job
  document.querySelectorAll('[onclick*="confirmJob(\''+id+'\'"]').forEach(function(btn){ btn.remove(); });
  toast('✅ '+j.name+' confirmed!');
  // Save to DB in background
  db.from('jobs').update({confirmed:true}).eq('job_id',id).then(function(r){
    if(r.error)console.error('confirmJob update error:',r.error.message);
  });
}

