function closeM(id){document.getElementById(id).classList.remove('open');document.body.classList.remove('modal-open');}
function openM(id){document.getElementById(id).classList.add('open');document.body.classList.add('modal-open');}
document.addEventListener('keydown',function(e){
  if(e.key==='Escape'){
    var openModals=document.querySelectorAll('.modal-overlay.open');
    if(openModals.length){
      var last=openModals[openModals.length-1];
      if(last.id==='bin-avail-warning-modal' && _binAvailWarningResolver){
        resolveBinAvailWarning(false); return;
      }
      last.classList.remove('open');
      // Only release body lock if no other overlays remain open (preserves stacked-modal scroll lock)
      if(!document.querySelectorAll('.modal-overlay.open').length){
        document.body.classList.remove('modal-open');
      }
    }
  }
});
function toggleBin(){
  var svc=document.getElementById('f-svc').value;
  var isBin=svc==='Bin Rental';
  var isJunk=svc==='Junk Removal';
  var hasItems=isJunk||svc==='Furniture Delivery'||svc==='Furniture Pickup';
  document.getElementById('bin-extra').style.display=isBin?'block':'none';
  document.getElementById('items-wrap').style.display=hasItems?'block':'none';
  var junkRecEl=document.getElementById('junk-recurring-extra');
  if(junkRecEl)junkRecEl.style.display=isJunk?'block':'none';
  var tnw=document.getElementById('tools-needed-wrap');if(tnw)tnw.style.display=(isJunk)?'block':'none';
  // Show junk schedule section for Junk Quote and Junk Removal
  var junkSchedWrap=document.getElementById('junk-schedule-wrap');
  if(junkSchedWrap){
    var isJunkSched=svc==='Junk Quote'||svc==='Junk Removal';
    junkSchedWrap.style.display=isJunkSched?'block':'none';
    if(isJunkSched){
      var isQuote=svc==='Junk Quote';
      document.getElementById('junk-schedule-label').textContent=isQuote?'Quote Schedule':'Job Schedule';
      document.getElementById('junk-date-label').textContent=isQuote?'Quote Date':'Job Date';
      document.getElementById('junk-time-label').textContent=isQuote?'Quote Time':'Job Time';
      var qaw=document.getElementById('quote-amount-wrap');if(qaw)qaw.style.display=isQuote?'block':'none';
    }
  }
  var isFurn=svc==='Furniture Delivery'||svc==='Furniture Pickup';
  var fbWrap=document.getElementById('fb-schedule-wrap');
  if(fbWrap){
    fbWrap.style.display=isFurn?'block':'none';
    if(isFurn){
      var isDeliv=svc==='Furniture Delivery';
      document.getElementById('fb-schedule-label').textContent=isDeliv?'Delivery Schedule':'Pickup Schedule';
      document.getElementById('fb-date-label').textContent=isDeliv?'Delivery Date':'Pickup Date';
      document.getElementById('fb-time-label').textContent=isDeliv?'Delivery Time':'Pickup Time';
    }
  }
  var drdWrap=document.getElementById('drd-inline-wrap');
  if(drdWrap){
    drdWrap.style.display=(svc==='Furniture Pickup'||svc==='Furniture Delivery')?'block':'none';
    if(svc==='Furniture Pickup'||svc==='Furniture Delivery') renderDrdModalGrid();
  }
  if(isBin){
    // Auto-fill drop-off date to today if empty
    var bdrop=document.getElementById('f-bdrop');
    if(bdrop&&!bdrop.value) bdrop.value=new Date().toISOString().split('T')[0];
    setTimeout(function(){initBinPicker('','');},50);
  }
  // Auto-fill email for Furniture Delivery new jobs
  if(svc==='Furniture Delivery' && !editId){
    var emailInps=document.querySelectorAll('#f-emails-wrap .f-email-inp');
    if(emailInps.length>0 && !emailInps[0].value){
      emailInps[0].value='warehouse@redwoodparkcommunities.com';
    } else if(emailInps.length===0){
      // Add an email row with the default
      addJobEmail();
      setTimeout(function(){
        var newInps=document.querySelectorAll('#f-emails-wrap .f-email-inp');
        if(newInps.length>0) newInps[0].value='warehouse@redwoodparkcommunities.com';
      },50);
    }
  }
}
// ── Photo upload helpers (Cloudinary) ──
function _cloudinaryConfigured(){
  return !!(CLOUDINARY_CLOUD_NAME && CLOUDINARY_PRESET);
}

async function _compressImage(file){
  var maxEdge = 1920, quality = 0.82;
  var bitmap = await createImageBitmap(file, {imageOrientation:'from-image'});
  var sw = bitmap.width, sh = bitmap.height;
  var scale = Math.min(1, maxEdge / Math.max(sw, sh));
  var w = Math.round(sw * scale), h = Math.round(sh * scale);
  var canvas = document.createElement('canvas');
  canvas.width = w; canvas.height = h;
  canvas.getContext('2d').drawImage(bitmap, 0, 0, w, h);
  return new Promise(function(resolve, reject){
    canvas.toBlob(function(blob){
      if(blob) resolve(blob); else reject(new Error('toBlob failed'));
    }, 'image/jpeg', quality);
  });
}

async function _uploadPhotoToCloudinary(file){
  if(!_cloudinaryConfigured()) throw new Error('Cloudinary not configured — fill in CLOUDINARY_CLOUD_NAME and CLOUDINARY_PRESET at the top of app.js');
  var blob = await _compressImage(file);
  var fd = new FormData();
  fd.append('file', blob);
  fd.append('upload_preset', CLOUDINARY_PRESET);
  var res = await fetch('https://api.cloudinary.com/v1_1/'+CLOUDINARY_CLOUD_NAME+'/image/upload', {method:'POST', body:fd});
  if(!res.ok) throw new Error('Upload failed: HTTP '+res.status);
  var data = await res.json();
  if(!data.secure_url) throw new Error('Upload failed: no secure_url returned');
  return data.secure_url;
}

function _cloudinaryDeliveryUrl(url, opts){
  if(!url || url.indexOf('/upload/') < 0) return url;
  var transforms = ['f_auto','q_auto'];
  if(opts && opts.width) transforms.push('w_'+opts.width);
  return url.replace('/upload/', '/upload/'+transforms.join(',')+'/');
}

async function _addPhotosFromInput(inp){
  if(!inp.files || !inp.files.length) return;
  if(!_cloudinaryConfigured()){
    toast('⚠ Photo upload not yet configured — Cloudinary cloud name + preset needed in app.js','error');
    inp.value = ''; return;
  }
  var grid = document.getElementById('f-photos-grid');
  var files = [].slice.call(inp.files);
  inp.value = '';
  for(var i = 0; i < files.length; i++){
    var placeholder = document.createElement('div');
    placeholder.className = 'photo-thumb photo-thumb-uploading';
    placeholder.textContent = 'Uploading…';
    if(grid) grid.appendChild(placeholder);
    try {
      var secureUrl = await _uploadPhotoToCloudinary(files[i]);
      _formPhotos.push(secureUrl);
      placeholder.remove();
      _renderFormPhotos();
    } catch(err){
      console.error('photo upload failed:', err);
      placeholder.textContent = '❌ Failed';
      (function(p){ setTimeout(function(){ p.remove(); }, 2500); })(placeholder);
      toast('Photo upload failed: '+err.message, 'error');
    }
  }
}

function _renderFormPhotos(){
  var grid = document.getElementById('f-photos-grid');
  if(!grid) return;
  grid.innerHTML = _formPhotos.map(function(url, i){
    var thumb = _cloudinaryDeliveryUrl(url, {width:200});
    return '<div class="photo-thumb" onclick="_openPhotoLightbox('+i+',\'form\')">'
      + '<img src="'+thumb+'" alt="" loading="lazy">'
      + '<button type="button" class="photo-thumb-remove" onclick="event.stopPropagation();_removeFormPhoto('+i+')" title="Remove">×</button>'
      + '</div>';
  }).join('');
}

function _removeFormPhoto(i){
  _formPhotos.splice(i, 1);
  _renderFormPhotos();
}

function _openPhotoLightbox(idx, source, jobId){
  var photos;
  if(source === 'form') photos = _formPhotos;
  else if(source === 'job'){
    var j = jobs.find(function(x){ return x.id === jobId; });
    photos = j ? (j.photos || []) : [];
  } else photos = [];
  if(!photos.length) return;
  window._lightboxPhotos = photos;
  window._lightboxIdx = Math.max(0, Math.min(idx, photos.length - 1));
  _renderLightbox();
  document.getElementById('photo-lightbox-modal').classList.add('open');
}

function _renderLightbox(){
  var photos = window._lightboxPhotos || [];
  var idx = window._lightboxIdx || 0;
  if(!photos.length) return;
  var img = document.getElementById('photo-lightbox-img');
  if(img) img.src = _cloudinaryDeliveryUrl(photos[idx], {});
  var counter = document.getElementById('photo-lightbox-counter');
  if(counter) counter.textContent = (idx + 1) + ' / ' + photos.length;
  var prev = document.getElementById('photo-lightbox-prev');
  var next = document.getElementById('photo-lightbox-next');
  if(prev) prev.style.visibility = idx > 0 ? 'visible' : 'hidden';
  if(next) next.style.visibility = idx < photos.length - 1 ? 'visible' : 'hidden';
}

function _lightboxNav(delta){
  var photos = window._lightboxPhotos || [];
  var idx = (window._lightboxIdx || 0) + delta;
  if(idx >= 0 && idx < photos.length){
    window._lightboxIdx = idx;
    _renderLightbox();
  }
}

function _renderJobPhotosDetail(j){
  var photos = j.photos || [];
  var thumbs = photos.map(function(url, i){
    var thumb = _cloudinaryDeliveryUrl(url, {width:200});
    return '<div class="photo-thumb" onclick="_openPhotoLightbox('+i+',\'job\',\''+j.id+'\')">'
      + '<img src="'+thumb+'" alt="" loading="lazy">'
      + '</div>';
  }).join('');
  var addBtn = '<label class="photo-add-btn" style="margin-left:auto">'
    + '<input type="file" accept="image/*" multiple style="display:none" onchange="_addPhotosToJob(\''+j.id+'\',this)">'
    + '<span>📷 Add Photos</span></label>';
  return '<div class="detail-section" id="detail-photos-'+j.id+'">'
    + '<div class="detail-section-title" style="display:flex;align-items:center">📷 Photos ('+photos.length+')'+addBtn+'</div>'
    + '<div class="photo-thumb-grid" id="detail-photos-grid-'+j.id+'">'+thumbs+'</div>'
    + '</div>';
}

async function _patchJobPhotos(jobId, photos){
  var local = jobs.find(function(j){ return j.id === jobId; });
  if(local) local.photos = photos.slice();
  var r = await db.from('jobs').update({photos: photos}).eq('job_id', jobId);
  if(r.error){
    toast('⚠ Photos save failed: '+r.error.message,'error');
    return false;
  }
  return true;
}

async function _addPhotosToJob(jobId, inp){
  if(!inp.files || !inp.files.length) return;
  if(!_cloudinaryConfigured()){
    toast('⚠ Photo upload not yet configured','error');
    inp.value = ''; return;
  }
  var job = jobs.find(function(j){ return j.id === jobId; });
  if(!job){ inp.value = ''; return; }
  var grid = document.getElementById('detail-photos-grid-'+jobId);
  var files = [].slice.call(inp.files);
  inp.value = '';
  for(var i = 0; i < files.length; i++){
    var placeholder = document.createElement('div');
    placeholder.className = 'photo-thumb photo-thumb-uploading';
    placeholder.textContent = 'Uploading…';
    if(grid) grid.appendChild(placeholder);
    try {
      var secureUrl = await _uploadPhotoToCloudinary(files[i]);
      var newPhotos = (job.photos || []).slice();
      newPhotos.push(secureUrl);
      var ok = await _patchJobPhotos(jobId, newPhotos);
      placeholder.remove();
      if(ok){
        var fresh = jobs.find(function(j){ return j.id === jobId; });
        var section = document.getElementById('detail-photos-'+jobId);
        if(section && fresh){
          var wrapper = document.createElement('div');
          wrapper.innerHTML = _renderJobPhotosDetail(fresh);
          section.parentNode.replaceChild(wrapper.firstChild, section);
        }
      }
    } catch(err){
      console.error('photo upload failed:', err);
      placeholder.textContent = '❌ Failed';
      (function(p){ setTimeout(function(){ p.remove(); }, 2500); })(placeholder);
      toast('Photo upload failed: '+err.message, 'error');
    }
  }
}

