// ── Service-type segmented picker ───────────────────────────────────
// Renders 5 color-coded buttons. The selected one fills with its brand color
// (white text). The hidden #f-svc input keeps the chosen service so all the
// existing saveJob/editJob/etc. code that reads f-svc.value works unchanged.
function _setSvcBtnState(btn, active){
  if(!btn) return;
  var color = btn.getAttribute('data-color');
  var rgbCsv = _hexOrRgbToRgbCsv(color) || '34,197,94';
  if(active){
    btn.style.background = color;
    btn.style.color = '#fff';
    btn.style.borderColor = color;
    btn.style.boxShadow = '0 6px 18px rgba('+rgbCsv+',.25)';
    btn.classList.add('svc-pick-active');
  } else {
    btn.style.background = '';
    btn.style.color = color;
    btn.style.borderColor = 'rgba('+rgbCsv+',.4)';
    btn.style.boxShadow = '';
    btn.classList.remove('svc-pick-active');
  }
}
// Public — called by the segmented picker buttons
function pickSvc(btn){
  if(!btn) return;
  var svc = btn.getAttribute('data-svc');
  document.querySelectorAll('.svc-pick-btn').forEach(function(b){
    _setSvcBtnState(b, b===btn);
  });
  document.getElementById('f-svc').value = svc;
  toggleBin();
  clearErr('f-svc');
}
// Programmatic — keeps the picker UI and hidden input in sync. Use this in
// newJob/editJob/quick-create flows instead of poking f-svc.value directly.
function setSvc(value){
  document.getElementById('f-svc').value = value || '';
  document.querySelectorAll('.svc-pick-btn').forEach(function(b){
    _setSvcBtnState(b, b.getAttribute('data-svc')===value);
  });
  toggleBin();
}

// Form-level Will Call toggle (used inside the New/Edit Job modal — distinct from
// the detail-view toggleWillCall(id,e) which patches an existing job by id).
// Called with no arg from the button (toggles current state) OR with a boolean
// from newJob/editJob to force a specific state.
function toggleWillCallForm(forceState){
  var chk=document.getElementById('f-bwillcall');
  var btn=document.getElementById('f-bwillcall-btn');
  var pick=document.getElementById('f-bpick');
  var pickTime=document.getElementById('f-bpick-time');
  if(!chk||!pick||!pickTime) return;
  var active = (forceState===undefined) ? !chk.checked : !!forceState;
  chk.checked = active;
  if(active){
    pick.value=''; pickTime.value='';
    pick.disabled=true; pickTime.disabled=true;
    pick.style.opacity='0.45'; pickTime.style.opacity='0.45';
    if(btn){
      btn.style.background='rgba(230,126,34,.18)';
      btn.style.borderColor='#e67e22';
      btn.innerHTML='📞 Will Call ON — click to turn off';
    }
  } else {
    pick.disabled=false; pickTime.disabled=false;
    pick.style.opacity='1'; pickTime.style.opacity='1';
    if(btn){
      btn.style.background='';
      btn.style.borderColor='rgba(230,126,34,.4)';
      btn.innerHTML='📞 Will Call — no pickup date scheduled';
    }
  }
}
function scheduleWillCallPickup(id,e){
  if(e)e.stopPropagation();
  var j=jobs.find(function(jj){return jj.id===id;});
  if(!j)return;
  var current=j.binPickup||'';
  var d=prompt('Pickup date (YYYY-MM-DD):',current);
  if(!d)return;
  if(!/^\d{4}-\d{2}-\d{2}$/.test(d.trim())){toast('⚠ Date must be YYYY-MM-DD','error');return;}
  d=d.trim();
  j.binPickup=d;
  j.binWillCall=false;
  patchJob(id,{binPickup:d,binWillCall:false});
  toast('Pickup scheduled for '+fd(d));
  refresh();
}
function toast(msg, type) {
  var t = document.getElementById('toast');
  var isErr  = type === 'error'  || msg.indexOf('⚠') === 0 || msg.indexOf('⚠️') === 0 || msg.indexOf('Error') >= 0;
  var isWarn = type === 'warn';
  t.className = 'toast' + (isErr ? ' toast-error' : isWarn ? ' toast-warn' : '');
  t.textContent = (isErr ? '✕ ' : isWarn ? '⚠ ' : '✓ ') + msg.replace(/^[⚠️✅✓⚠]\s*/,'');
  t.classList.add('show');
  clearTimeout(t._tid);
  t._tid = setTimeout(function(){ t.classList.remove('show'); }, 3000);
}
// Overlay click-to-close intentionally disabled — use Cancel/Submit buttons or ✕ to close modals.
