// ═══════════════════════════════════════
//  AUTH SYSTEM — Supabase Login
// ═══════════════════════════════════════
var currentUser = null;
var canDelete = false;
var appLoaded = false;

// Check if already logged in on page load
db.auth.getSession().then(function(r) {
  if (r.data && r.data.session) {
    currentUser = r.data.session.user;
    onLoginSuccess();
  } else {
    document.getElementById('login-screen').style.display = 'flex';
    setTimeout(function(){ document.getElementById('login-username').focus(); }, 100);
  }
});

// Periodic session check — signs out if token expired (catches stale tabs)
setInterval(function() {
  if (!currentUser) return;
  db.auth.getSession().then(function(r) {
    if (!r.data || !r.data.session) {
      toast('⚠ Session expired — please sign in again.');
      db.auth.signOut();
    }
  });
}, 60000); // check every 60 seconds

// Listen for auth changes (e.g. session expiry)
db.auth.onAuthStateChange(function(event, session) {
  if (event === 'SIGNED_IN' && appLoaded) {
    // Already handled by doLogin() or getSession() — ignore duplicate
    return;
  }
  if (event === 'SIGNED_IN' && !appLoaded && session) {
    currentUser = session.user;
    onLoginSuccess();
    return;
  }
  if (event === 'TOKEN_REFRESHED' && !session) {
    toast('⚠ Session expired — please sign in again.');
    db.auth.signOut();
    return;
  }
  if (event === 'SIGNED_OUT') {
    clearTimeout(_inactivityTimer);
    currentUser = null;
    canDelete = false;
    appLoaded = false;
    document.getElementById('login-screen').style.display = 'flex';
    document.getElementById('login-username').focus();
    setUserCardSignedOut();
    applyDeleteVisibility();
  }
});

async function doLogin() {
  var username = document.getElementById('login-username').value.trim();
  var pass  = document.getElementById('login-password').value;
  var errEl = document.getElementById('login-error');
  var btn   = document.getElementById('login-btn');
  if (!username || !pass) { errEl.textContent = 'Please enter your username and password.'; return; }
  errEl.textContent = '';
  btn.textContent = 'Signing in...';
  btn.style.background = '#16a34a';
  btn.disabled = true;

  function loginFail(msg) {
    errEl.textContent = msg;
    errEl.style.fontWeight = '600';
    errEl.style.fontSize = '14px';
    btn.textContent = 'Sign In';
    btn.style.background = '#22c55e';
    btn.disabled = false;
    document.getElementById('login-password').value = '';
    document.getElementById('login-password').focus();
  }

  // Check Supabase client exists
  if (!db || !db.auth) {
    loginFail('⚠ App failed to initialise — please hard-refresh (Ctrl+Shift+R).');
    return;
  }

  // 12 second timeout
  var timedOut = false;
  var timer = setTimeout(function() {
    timedOut = true;
    loginFail('⚠ Connection timed out. Check your internet and try again.');
  }, 12000);

  // Look up email from username
  var emailRes;
  try {
    emailRes = await db.rpc('get_email_by_username', { lookup_username: username });
  } catch(ex) {
    clearTimeout(timer);
    loginFail('⚠ Network error: ' + ex.message);
    return;
  }
  if (!emailRes.data) {
    clearTimeout(timer);
    loginFail('⚠ Username not found.');
    return;
  }
  var email = emailRes.data;

  var r;
  try {
    r = await db.auth.signInWithPassword({ email: email, password: pass });
  } catch(ex) {
    clearTimeout(timer);
    loginFail('⚠ Network error: ' + ex.message);
    return;
  }

  clearTimeout(timer);
  if (timedOut) return;

  console.log('Auth result:', r);

  if (r.error) {
    var msg = r.error.message || 'Unknown error';
    // Make common errors human-readable
    if (msg.toLowerCase().includes('invalid login')) msg = 'Invalid username or password.';
    else if (msg.toLowerCase().includes('email not confirmed')) msg = 'Please confirm your email address first.';
    else if (msg.toLowerCase().includes('too many requests')) msg = 'Too many attempts — wait a minute and try again.';
    loginFail('⚠ ' + msg);
    return;
  }

  if (!r.data || !r.data.user) {
    loginFail('⚠ Sign-in returned no user — please try again.');
    return;
  }

  currentUser = r.data.user;
  onLoginSuccess();
}

function setUserCardSignedIn(username, role){
  var card = document.getElementById('user-card');
  var label = document.getElementById('admin-btn-label');
  var signIcon = document.getElementById('admin-btn-icon');
  var avatar = document.getElementById('user-avatar');
  var meta = document.getElementById('user-meta');
  var nameEl = document.getElementById('logged-in-username');
  var roleEl = document.getElementById('user-role');
  var signoutBtn = document.getElementById('user-signout');
  if(!card) return;
  card.classList.remove('signed-out');
  card.onclick = null;
  if(label) label.style.display='none';
  if(signIcon) signIcon.style.display='none';
  if(avatar){ avatar.textContent = (username||'?').charAt(0); avatar.style.display=''; }
  if(meta) meta.style.display='';
  if(nameEl) nameEl.textContent = username || '—';
  if(roleEl) roleEl.textContent = role || 'User';
  if(signoutBtn) signoutBtn.style.display='';
}
function setUserCardSignedOut(){
  var card = document.getElementById('user-card');
  var label = document.getElementById('admin-btn-label');
  var signIcon = document.getElementById('admin-btn-icon');
  var avatar = document.getElementById('user-avatar');
  var meta = document.getElementById('user-meta');
  var signoutBtn = document.getElementById('user-signout');
  if(!card) return;
  card.classList.add('signed-out');
  card.onclick = handleAdminBtn;
  if(label){ label.textContent='Admin Login'; label.style.display=''; }
  if(signIcon) signIcon.style.display='';
  if(avatar) avatar.style.display='none';
  if(meta) meta.style.display='none';
  if(signoutBtn) signoutBtn.style.display='none';
}

async function onLoginSuccess() {
  if (appLoaded) return; // prevent double-load
  appLoaded = true;
  // Await profile so displayName is set before any job saves can happen
  var r = await db.from('user_profiles').select('role,can_delete,username').eq('id', currentUser.id).single();
  if (r.data && r.data.can_delete) {
    canDelete = true;
  }
  var uname = (r.data && r.data.username) ? r.data.username : (currentUser.email||'').split('@')[0];
  var role  = (r.data && r.data.role) ? r.data.role : 'User';
  currentUser.displayName = uname;
  setUserCardSignedIn(uname, role);
  applyDeleteVisibility();
  applyAnalyticsVisibility();
  document.getElementById('login-screen').style.display = 'none';
  resetInactivityTimer();
  loadAllFromSupabase();
}

function applyDeleteVisibility() {
  document.querySelectorAll('.delete-only').forEach(function(el) {
    el.style.display = canDelete ? '' : 'none';
  });
}
function applyAnalyticsVisibility(){
  var nav=document.getElementById('nav-analytics');
  var navLabel=document.getElementById('nav-analytics-label');
  if(canAccessAnalytics()){
    if(navLabel)navLabel.style.display='';
  } else {
    if(nav)nav.style.display='none';
    if(navLabel)navLabel.style.display='none';
  }
}

function handleAdminBtn() {
  // This button is now Sign Out
  if (!currentUser) return;
  if (confirm('Sign out of Jeff\'s Junk?')) {
    db.auth.signOut();
  }
}

// ── 30-minute inactivity auto-logout ──
var _inactivityTimer = null;
var INACTIVITY_LIMIT = 30 * 60 * 1000; // 30 minutes

function resetInactivityTimer() {
  clearTimeout(_inactivityTimer);
  if (!currentUser) return;
  _inactivityTimer = setTimeout(function() {
    if (!currentUser) return;
    toast('⚠ Signed out due to inactivity.');
    db.auth.signOut();
  }, INACTIVITY_LIMIT);
}

['mousedown','keydown','touchstart','scroll'].forEach(function(evt) {
  document.addEventListener(evt, resetInactivityTimer, { passive: true });
});

