  card(p1,M,y-botH,colW,botH);
  txt(p1,'Top Cities',M+12,y-16,9.5,fb,DARK);
  var cities=Object.entries(d.cur.byCity).sort(function(a,b){return b[1]-a[1];}).slice(0,7);
  var maxCity=cities.length?cities[0][1]:1;
